320→  private async connectWebSocket(): Promise<void> {
321→    const url = `ws://127.0.0.1:${this.port}`;
322→
323→    return new Promise<void>((resolve, reject) => {
324→      const ws = new WebSocket(url);
325→      const timeout = setTimeout(() => {
