352→    this.keepaliveTick = 0;
353→    this.keepaliveTimer = setInterval(() => {
354→      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
355→      this.keepaliveTick++;
356→      try {
357→        this.ws.send(JSON.stringify({
358→          type: "input_mouse",
359→          eventType: "mouseMoved",
360→          x: 10 + (this.keepaliveTick % 2),
361→          y: 10,
362→          button: "none",
