378→  private setupMessageHandler(): void {
379→    if (!this.ws) return;
380→
381→    // Start keepalive to ensure continuous frame delivery
382→    this.startKeepalive();
383→
384→    this.ws.onmessage = (event: MessageEvent) => {
385→      if (!this.active || !this.ffmpeg?.stdin?.writable) return;
386→
387→      try {
388→        const raw = typeof event.data === "string" ? event.data : event.data.toString();
389→        const msg = JSON.parse(raw);
390→
391→        if (msg.type === "frame" && msg.data) {
392→          // Capture frame dimensions from metadata (first frame sets it)
393→          if (this.detectedWidth === null && msg.metadata) {
394→            const w = msg.metadata.deviceWidth;
395→            const h = msg.metadata.deviceHeight;
396→            if (typeof w === "number" && typeof h === "number" && w > 0 && h > 0) {
397→              this.detectedWidth = w;
398→              this.detectedHeight = h;
399→              console.error(`[stream-recorder] Detected frame size: ${w}x${h}`);
400→            }
401→          }
402→
403→          const bytes = Buffer.from(msg.data, "base64");
404→          const ok = this.ffmpeg.stdin.write(bytes);
405→          if (ok) {
406→            this.frameCount++;
407→            const now = Date.now();
408→            if (this.firstFrameTime === null) this.firstFrameTime = now;
409→            this.lastFrameTime = now;
410→
411→            // Resolve ready promise on first frame
412→            if (this.frameCount === 1 && this.readyResolve) {
413→              const r = this.readyResolve;
414→              this.readyResolve = null;
415→              r();
416→            }
417→          } else {
418→            this.droppedFrames++;
419→          }
420→        }
421→        if (msg.type === "status") {
422→          console.error(
423→            `[stream-recorder] Status: connected=${msg.connected}, screencasting=${msg.screencasting}`
424→          );
425→        }
426→      } catch {
427→        // Malformed message — skip
428→      }
429→    };
430→
431→    this.ws.onclose = () => {
432→      this.ws = null;
433→      if (this.active) {
434→        console.error("[stream-recorder] WebSocket disconnected, attempting reconnect");
435→        this.scheduleReconnect();
436→      }
437→    };
438→
439→    this.ws.onerror = () => {
440→      // onclose will fire after onerror, reconnect handled there
441→    };
442→  }
443→
444→  private scheduleReconnect(attempt = 1): void {
445→    if (!this.active || this.reconnecting || attempt > RECONNECT_MAX_ATTEMPTS) {
446→      if (attempt > RECONNECT_MAX_ATTEMPTS) {
447→        console.error(
448→          `[stream-recorder] Max reconnect attempts (${RECONNECT_MAX_ATTEMPTS}) exceeded, capture paused`
449→        );
450→      }
451→      return;
452→    }
453→
454→    this.reconnecting = true;
455→    this.reconnectTimer = setTimeout(
456→      async () => {
457→        this.reconnectTimer = null;
458→        if (!this.active) {
459→          this.reconnecting = false;
460→          return;
461→        }
462→
463→        try {
464→          await this.connectWebSocket();
465→          console.error(`[stream-recorder] Reconnected (attempt ${attempt})`);
466→          this.reconnecting = false;
467→        } catch {
468→          this.reconnecting = false;
469→          this.scheduleReconnect(attempt + 1);
470→        }
471→      },
472→      Math.min(RECONNECT_DELAY_MS * attempt, 5_000)
473→    );
474→  }
