 15→export async function probeVideoDimensions(
 16→  filePath: string
 17→): Promise<{ width: number; height: number } | null> {
 18→  return new Promise((resolve) => {
 19→    const proc = spawn(
 20→      "ffprobe",
 21→      [
 22→        "-v", "error",
 23→        "-select_streams", "v:0",
 24→        "-show_entries", "stream=width,height",
 25→        "-of", "csv=p=0",
 26→        filePath,
 27→      ],
 28→      { stdio: ["ignore", "pipe", "pipe"] }
 29→    );
 30→
 31→    let output = "";
 32→    proc.stdout.on("data", (chunk: Buffer) => {
 33→      output += chunk.toString();
 34→    });
 35→
 36→    proc.on("error", () => resolve(null));
 37→    proc.on("close", (code) => {
 38→      if (code !== 0) return resolve(null);
 39→      // Output format: "width,height\n" e.g. "1280,720\n"
 40→      const parts = output.trim().split(",");
 41→      if (parts.length >= 2) {
 42→        const width = parseInt(parts[0], 10);
 43→        const height = parseInt(parts[1], 10);
 44→        if (width > 0 && height > 0) {
 45→          return resolve({ width, height });
 46→        }
 47→      }
 48→      resolve(null);
 49→    });
 50→  });
 51→}
