 53→/**
 54→ * Check if ffmpeg is available on the system PATH.
 55→ * Returns the version string if found, null otherwise.
 56→ */
 57→export async function detectFfmpeg(): Promise<string | null> {
 58→  return new Promise((resolve) => {
 59→    const proc = spawn("ffmpeg", ["-version"], { stdio: ["ignore", "pipe", "ignore"] });
 60→    let output = "";
 61→
 62→    proc.stdout.on("data", (chunk: Buffer) => {
 63→      output += chunk.toString();
 64→    });
 65→
 66→    proc.on("error", () => resolve(null));
 67→    proc.on("close", (code) => {
 68→      if (code === 0 && output.length > 0) {
 69→        const match = output.match(/ffmpeg version (\S+)/);
 70→        resolve(match ? match[1] : "unknown");
 71→      } else {
 72→        resolve(null);
 73→      }
 74→    });
 75→  });
 76→}
