 78→/**
 79→ * Auto-detect the screen capture device index for avfoundation on macOS.
 80→ *
 81→ * Runs `ffmpeg -f avfoundation -list_devices true -i ""` and parses
 82→ * the output to find the first "Capture screen N" device.
 83→ *
 84→ * Returns the device index string (e.g. "4") or null if not found.
 85→ */
 86→export function detectScreenDevice(): string | null {
 87→  if (platform() !== "darwin") return null;
 88→
 89→  try {
 90→    // ffmpeg -list_devices writes to stderr and exits with code 1 (expected)
 91→    const output = execFileSync("ffmpeg", ["-f", "avfoundation", "-list_devices", "true", "-i", ""], {
 92→      encoding: "utf-8",
 93→      stdio: ["ignore", "pipe", "pipe"],
 94→      timeout: 5000,
 95→    });
 96→    return parseScreenDevice(output);
 97→  } catch (err: unknown) {
 98→    // ffmpeg writes device list to stderr and exits 1 — that's normal
 99→    const stderr = (err as { stderr?: string })?.stderr ?? "";
100→    return parseScreenDevice(stderr);
101→  }
102→}
103→
104→/**
105→ * Parse avfoundation device list output to find the screen capture device.
106→ * Looks for lines like: [AVFoundation ...] [4] Capture screen 0
107→ */
108→function parseScreenDevice(output: string): string | null {
109→  const lines = output.split("\n");
110→  for (const line of lines) {
111→    // Match: [AVFoundation ...] [N] Capture screen M
112→    const match = line.match(/\[(\d+)]\s+Capture screen/);
113→    if (match) {
114→      return match[1];
115→    }
116→  }
117→  return null;
118→}
