120→/**
121→ * Build ffmpeg args for screen capture.
122→ *
123→ * Linux (x11grab):
124→ *   ffmpeg -f x11grab -video_size WxH -framerate FPS -i :99 -c:v libx264 ...
125→ *
126→ * macOS (avfoundation):
127→ *   ffmpeg -f avfoundation -framerate FPS -capture_cursor 1 -i "N:none" ...
128→ *   where N is the auto-detected screen device index.
129→ */
130→export function buildCaptureArgs(config: FfmpegCaptureConfig): string[] {
131→  const args: string[] = ["-y"]; // overwrite output
132→
133→  if (config.method === "x11grab") {
134→    args.push(
135→      "-f", "x11grab",
136→      "-video_size", `${config.sourceSize.width}x${config.sourceSize.height}`,
137→      "-framerate", String(config.fps),
138→      "-i", config.display,
139→    );
140→  } else {
141→    // avfoundation (macOS)
142→    // Auto-detect screen device index, fallback to config.display or "1"
143→    const screenDevice = config.screenDevice ?? detectScreenDevice() ?? "1";
144→
145→    args.push(
146→      "-f", "avfoundation",
147→      "-framerate", String(config.fps),
148→      "-capture_cursor", "1",
149→      // "N:none" = video device N, no audio
150→      "-i", `${screenDevice}:none`,
151→    );
152→  }
153→
154→  args.push(
155→    "-c:v", "libx264",
156→    "-preset", "ultrafast",
157→    "-crf", "18",
158→    config.outputPath,
159→  );
160→
161→  return args;
162→}
