164→/**
165→ * Manages ffmpeg child processes for screen capture.
166→ *
167→ * Lifecycle:
168→ * 1. startCapture() — spawns ffmpeg to record the screen
169→ * 2. stopCapture() — sends 'q' to ffmpeg stdin to stop gracefully
170→ * 3. cleanup() — removes temp files
171→ */
172→export class FfmpegRecorder {
173→  private captureProcess: ChildProcess | null = null;
174→  private rawCapturePath: string | null = null;
175→  private captureStderr = "";
176→  private captureExitError: string | null = null;
177→
178→  /**
179→   * Start screen capture.
180→   * Spawns ffmpeg as a child process.
181→   *
182→   * On macOS, auto-detects the screen capture device. On Linux, uses the
183→   * display from config (default ":99" for Xvfb).
184→   *
185→   * Waits up to 2s for ffmpeg to start writing frames. If ffmpeg exits
186→   * during startup, throws with the ffmpeg error.
187→   */
188→  async startCapture(config: FfmpegCaptureConfig): Promise<void> {
189→    if (this.captureProcess) {
190→      throw new Error("ffmpeg capture is already running");
191→    }
192→
193→    const args = buildCaptureArgs(config);
194→    this.rawCapturePath = config.outputPath;
195→    this.captureStderr = "";
196→
197→    return new Promise<void>((resolve, reject) => {
198→      const proc = spawn("ffmpeg", args, {
199→        stdio: ["pipe", "pipe", "pipe"],
200→      });
201→
202→      this.captureProcess = proc;
203→      let resolved = false;
204→
205→      proc.stderr?.on("data", (chunk: Buffer) => {
206→        this.captureStderr += chunk.toString();
207→
208→        // ffmpeg writes "frame= N" when it starts actually capturing
209→        if (!resolved && this.captureStderr.includes("frame=")) {
210→          resolved = true;
211→          resolve();
212→        }
213→      });
214→
215→      // Fallback: if no "frame=" after 2s, check if process is still alive
216→      const startupTimer = setTimeout(() => {
217→        if (!resolved) {
218→          resolved = true;
219→          if (this.captureProcess) {
220→            // Process is still running — likely capturing (some ffmpeg builds
221→            // don't write "frame=" immediately)
222→            resolve();
223→          } else {
224→            reject(new Error(
225→              `ffmpeg capture failed to start within 2s.\n` +
226→              `Last stderr: ${this.captureStderr.slice(-300)}\n` +
227→              `Hint: On macOS, ensure Screen Recording permission is granted in System Settings → Privacy & Security.`,
228→            ));
229→          }
230→        }
231→      }, 2000);
232→
233→      proc.on("error", (err) => {
234→        clearTimeout(startupTimer);
235→        this.captureProcess = null;
236→        if (!resolved) {
237→          resolved = true;
238→          reject(new Error(`Failed to start ffmpeg: ${err.message}`));
239→        }
240→      });
241→
242→      proc.on("close", (code, signal) => {
243→        clearTimeout(startupTimer);
244→        this.captureProcess = null;
245→        if (!resolved) {
246→          resolved = true;
247→          reject(new Error(
248→            `ffmpeg capture exited before startup completed (code ${code ?? "null"}, signal ${signal ?? "none"}).\n` +
249→            `stderr: ${this.captureStderr.slice(-500)}\n` +
250→            `Hint: Check that the capture device is accessible.`,
251→          ));
252→        } else if (code !== 0) {
253→          // After startup resolved, capture unexpected exit
254→          this.captureExitError = `ffmpeg capture exited unexpectedly (code ${code ?? "null"}).\nstderr: ${this.captureStderr.slice(-300)}`;
255→        }
256→      });
257→    });
258→  }
259→
260→  /**
261→   * Stop the active capture process.
262→   * Sends 'q' to ffmpeg stdin for graceful shutdown.
263→   * Returns the raw capture path, or null if capture wasn't running.
264→   *
265→   * After stopping, verifies the raw file exists and has content.
266→   * Throws if the raw file is missing or empty.
267→   */
268→  async stopCapture(): Promise<string | null> {
269→    if (!this.captureProcess) {
270→      // Check if capture died while we weren't looking
271→      if (this.captureExitError) {
272→        const err = this.captureExitError;
273→        this.captureExitError = null;
274→        throw new Error(`Capture failed during recording: ${err}`);
275→      }
276→      return this.rawCapturePath;
277→    }
278→
279→    const path = await new Promise<string | null>((resolve) => {
280→      const proc = this.captureProcess!;
281→
282→      const killTimer = setTimeout(() => {
283→        proc.kill("SIGKILL");
284→      }, 10_000);
285→
286→      proc.on("close", () => {
287→        clearTimeout(killTimer);
288→        this.captureProcess = null;
289→        resolve(this.rawCapturePath);
290→      });
291→
292→      if (proc.stdin?.writable) {
293→        proc.stdin.write("q");
294→        proc.stdin.end();
295→      } else {
296→        proc.kill("SIGINT");
297→      }
298→    });
299→
300→    // Verify the raw file actually exists
301→    if (path && !existsSync(path)) {
302→      throw new Error(
303→        `Screen capture failed: raw file not found at ${path}.\n` +
304→        `ffmpeg stderr: ${this.captureStderr.slice(-300)}\n` +
305→        `Hint: On macOS, ensure Screen Recording permission is granted. On Linux, ensure Xvfb is running on the configured display.`,
306→      );
307→    }
308→
309→    // Verify the raw file is not empty (e.g. permission denied produces 0-byte file)
310→    if (path) {
311→      const { size } = await stat(path);
312→      if (size === 0) {
313→        throw new Error(
314→          `Screen capture failed: raw file at ${path} is empty.\n` +
315→          `ffmpeg stderr: ${this.captureStderr.slice(-300)}\n` +
316→          `Hint: On macOS, ensure Screen Recording permission is granted.`,
317→        );
318→      }
319→    }
320→
321→    return path;
322→  }
323→
324→  /**
325→   * Check if a capture is currently running.
326→   */
327→  isCapturing(): boolean {
328→    return this.captureProcess !== null;
329→  }
330→
331→  /**
332→   * Clean up temporary capture file.
333→   */
334→  async cleanup(): Promise<void> {
335→    if (this.rawCapturePath && existsSync(this.rawCapturePath)) {
336→      try {
337→        await unlink(this.rawCapturePath);
338→      } catch {
339→        // Ignore cleanup errors
340→      }
341→    }
342→    this.rawCapturePath = null;
343→  }
344→
345→  /**
346→   * Force-kill the capture process if running.
347→   */
348→  kill(): void {
349→    if (this.captureProcess) {
350→      this.captureProcess.kill("SIGKILL");
351→      this.captureProcess = null;
352→      this.captureExitError = null;
353→    }
354→  }
355→}
