  1→import { randomBytes } from "node:crypto";
  2→import { tmpdir } from "node:os";
  3→import { join } from "node:path";
  4→import type { AgentEvent, AgentEventType } from "../types.js";
  5→import { CameraEngine } from "../camera/engine.js";
  6→import { TimelineRecorder } from "../recorder/encoder.js";
  7→import { FfmpegRecorder, detectFfmpeg, probeVideoDimensions } from "./ffmpeg-recorder.js";
  8→import { StreamRecorder } from "./stream-capture.js";
  9→import type {
 10→  Chapter,
 11→  RecordingResult,
 12→  RecordingSessionState,
 13→  RecordingStartParams,
 14→  RecordingStatus,
 15→  ResolvedRecordingConfig,
 16→} from "./types.js";
 17→
 18→/**
 19→ * Generate a short, readable session ID.
 20→ * Format: rec_{6 hex chars} (e.g. "rec_a1b2c3")
 21→ */
 22→function generateSessionId(): string {
 23→  return `rec_${randomBytes(3).toString("hex")}`;
 24→}
 25→
 26→/**
 27→ * Resolve user-provided params into a fully resolved config with defaults.
 28→ *
 29→ * Source size defaults to 1280x720 (agent-browser's default viewport).
 30→ * When using stream capture, the actual frame dimensions are auto-detected
 31→ * from the stream metadata and override this at post-processing time.
 32→ */
 33→function resolveConfig(params: RecordingStartParams): ResolvedRecordingConfig {
 34→  const timestamp = Date.now();
 35→  return {
 36→    outputPath: params.outputPath ?? join(tmpdir(), `recording-${timestamp}.mp4`),
 37→    sourceSize: {
 38→      width: params.sourceWidth ?? 1280,
 39→      height: params.sourceHeight ?? 720,
 40→    },
 41→    outputSize: {
 42→      width: params.outputWidth ?? 1920,
 43→      height: params.outputHeight ?? 1080,
 44→    },
 45→    fps: params.fps ?? 30,
 46→    deviceFrame: params.deviceFrame ?? "none",
 47→    background: params.background ?? { type: "gradient", colors: ["#0f0f23", "#1a1a3e"] },
 48→    captureMethod: params.captureMethod ?? "none",
 49→    display: params.display ?? ":99",
 50→  };
 51→}
 52→
 53→/**
 54→ * Internal per-session state.
 55→ */
 56→interface InternalSession {
 57→  state: RecordingSessionState;
 58→  engine: CameraEngine;
 59→  timelineRecorder: TimelineRecorder;
 60→  /** avfoundation / x11grab recorder (two-pass: capture then post-process) */
 61→  ffmpegRecorder: FfmpegRecorder;
 62→  rawCapturePath: string | null;
 63→  /** WebSocket stream recorder (agent-browser frame stream → ffmpeg) */
 64→  streamRecorder: StreamRecorder | null;
 65→}
 66→
 67→/**
 68→ * Manages multiple concurrent recording sessions.
 69→ *
 70→ * Capture backends:
 71→ *   - "stream": WebSocket stream from agent-browser, 10fps, no permission, no CDP conflicts
 72→ *   - "avfoundation": macOS native capture, 30fps, needs Screen Recording permission
 73→ *   - "x11grab": Linux Xvfb, 30fps
 74→ *   - "auto": try stream (if available), then avfoundation, fall back to none
 75→ *   - "none": events-only, no video capture
 76→ *
 77→ * All capture backends produce a raw MP4, which is then post-processed
 78→ * with camera effects (zoompan/crop filter) from the timeline.
 79→ */
 80→export class SessionManager {
 81→  private sessions = new Map<string, InternalSession>();
 82→  private ffmpegAvailable: boolean | null = null;
 83→
 84→  /**
 85→   * Create a new recording session.
 86→   */
 87→  async create(params: RecordingStartParams): Promise<string> {
 88→    const id = generateSessionId();
 89→    const config = resolveConfig(params);
 90→
 91→    const engine = new CameraEngine({ sourceSize: config.sourceSize });
 92→    const timelineRecorder = new TimelineRecorder({ fps: config.fps });
 93→    const ffmpegRecorder = new FfmpegRecorder();
 94→
 95→    const state: RecordingSessionState = {
 96→      id,
 97→      status: "recording",
 98→      config,
 99→      events: [],
100→      chapters: [],
101→      startTime: Date.now(),
102→    };
103→
104→    let rawCapturePath: string | null = null;
105→    let streamRecorder: StreamRecorder | null = null;
106→
107→    // Resolve capture method
108→    let method = config.captureMethod;
109→    if (method === "auto") {
110→      method = await this.resolveAutoCapture();
111→    }
112→
113→    if (method === "stream") {
114→      // WebSocket stream from agent-browser — no OS permission, no CDP conflicts
115→      const streamPort = this.resolveStreamPort();
116→      if (streamPort) {
117→        rawCapturePath = join(tmpdir(), `raw-${id}.mp4`);
118→        streamRecorder = new StreamRecorder({
119→          outputPath: rawCapturePath,
120→        });
121→
122→        try {
123→          await streamRecorder.start(streamPort);
124→        } catch (err) {
125→          console.error(`[session-manager] Stream capture failed: ${err}`);
126→          streamRecorder = null;
127→          rawCapturePath = null;
128→          // Continue without capture — events still record
129→        }
130→      } else {
131→        console.error("[session-manager] No stream port found, falling back to events-only");
132→      }
133→    } else if (method === "avfoundation" || method === "x11grab") {
134→      // Native ffmpeg capture
135→      if (this.ffmpegAvailable === null) {
136→        this.ffmpegAvailable = (await detectFfmpeg()) !== null;
137→      }
138→      if (!this.ffmpegAvailable) {
139→        throw new Error("ffmpeg is not available. Install ffmpeg or use captureMethod: 'none'.");
140→      }
141→
142→      rawCapturePath = join(tmpdir(), `raw-${id}.mp4`);
143→
144→      try {
145→        await ffmpegRecorder.startCapture({
146→          method,
147→          sourceSize: config.sourceSize,
148→          fps: config.fps,
149→          display: config.display,
150→          outputPath: rawCapturePath,
151→        });
152→      } catch (err) {
153→        if (method === "avfoundation" && config.captureMethod === "auto") {
154→          // avfoundation failed (likely no Screen Recording permission).
155→          // Fall back to events-only.
156→          console.error(
157→            `[session-manager] avfoundation failed (grant Screen Recording permission in System Settings): ${err}`
158→          );
159→          rawCapturePath = null;
160→        } else {
161→          throw err;
162→        }
163→      }
164→    }
165→
166→    timelineRecorder.start();
167→
168→    this.sessions.set(id, {
169→      state,
170→      engine,
171→      timelineRecorder,
172→      ffmpegRecorder,
173→      rawCapturePath,
174→      streamRecorder,
175→    });
176→
177→    return id;
178→  }
179→
180→  /**
181→   * Push an agent event into a recording session.
182→   * Drives the camera engine's auto-zoom/pan behavior.
183→   */
184→  event(
185→    sessionId: string,
186→    type: AgentEventType,
187→    x: number,
188→    y: number,
189→    meta?: {
190→      elementRect?: { x: number; y: number; width: number; height: number };
191→      text?: string;
192→      url?: string;
193→      direction?: string;
194→    }
195→  ): number {
196→    const session = this.getSession(sessionId);
197→    if (session.state.status !== "recording") {
198→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
199→    }
200→
201→    const t = Date.now() - session.state.startTime;
202→
203→    const eventMeta: Record<string, unknown> = {};
204→    if (meta?.text) eventMeta.text = meta.text;
205→    if (meta?.url) eventMeta.url = meta.url;
206→    if (meta?.direction) eventMeta.direction = meta.direction;
207→
208→    const agentEvent: AgentEvent = {
209→      type,
210→      t,
211→      x,
212→      y,
213→      elementRect: meta?.elementRect,
214→      meta: eventMeta,
215→    };
216→
217→    session.state.events.push(agentEvent);
218→    session.engine.pushEvent(agentEvent);
219→    session.engine.step(1 / session.state.config.fps);
220→
221→    const camera = session.engine.getTransform();
222→    const cursor = session.engine.getCursorState();
223→    session.timelineRecorder.captureFrame(t, camera, {
224→      x: cursor.x,
225→      y: cursor.y,
226→      clicking: cursor.clicking,
227→      visible: cursor.visible,
228→    });
229→
230→    return session.state.events.length - 1;
231→  }
232→
233→  /**
234→   * Add a chapter marker to the session.
235→   */
236→  chapter(sessionId: string, title: string): { chapterIndex: number; timestamp: number } {
237→    const session = this.getSession(sessionId);
238→    if (session.state.status !== "recording") {
239→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
240→    }
241→
242→    const timestamp = Date.now() - session.state.startTime;
243→    const chapter: Chapter = {
244→      title,
245→      timestamp,
246→      eventIndex: session.state.events.length,
247→    };
248→
249→    session.state.chapters.push(chapter);
250→
251→    return {
252→      chapterIndex: session.state.chapters.length - 1,
253→      timestamp,
254→    };
255→  }
256→
257→  /**
258→   * Stop a recording session and produce the final MP4.
259→   *
260→   * Pipeline:
261→   *   1. Stop capture (stream or avfoundation/x11grab)
262→   *   2. Generate camera timeline from recorded events
263→   *   3. Apply zoompan/crop filter to raw capture → final MP4
264→   */
265→  async stop(
266→    sessionId: string,
267→    options?: { addWatermark?: boolean; watermarkText?: string }
268→  ): Promise<RecordingResult> {
269→    const session = this.getSession(sessionId);
270→    if (session.state.status !== "recording") {
271→      throw new Error(`Session ${sessionId} is not recording (status: ${session.state.status})`);
272→    }
273→
274→    session.state.status = "processing";
275→    session.state.endTime = Date.now();
276→
277→    try {
278→      // Stop the event-driven timeline recorder (we'll regenerate a continuous
279→      // timeline below using processTimeline at the raw video's fps).
280→      session.timelineRecorder.stop();
281→      const config = session.state.config;
282→      const duration = (session.state.endTime! - session.state.startTime) / 1000;
283→      let videoProduced = false;
284→
285→      // The raw video's fps: use measured delivery rate for stream, config for native.
286→      const rawFps = session.streamRecorder
287→        ? (session.streamRecorder.actualFps ?? 10)
288→        : config.fps;
289→
290→      // --- Stop stream recorder ---
291→      let actualSourceSize = config.sourceSize;
292→      if (session.streamRecorder) {
293→        try {
294→          const rawPath = await session.streamRecorder.stop();
295→          if (rawPath) {
296→            session.rawCapturePath = rawPath;
297→          } else {
298→            // stop() returned null → 0 frames captured
299→            console.error("[session-manager] Stream recorder captured 0 frames, skipping post-process");
300→            session.rawCapturePath = null;
301→          }
302→        } catch (err) {
303→          console.error("[session-manager] Stream capture stop failed:", err);
304→          session.rawCapturePath = null;
305→        }
306→
307→        // Warn if frame count is too low for the session duration
308→        const expectedMin = Math.max(1, Math.floor(duration * 5));
309→        if (session.streamRecorder.frames > 0 && session.streamRecorder.frames < expectedMin) {
310→          console.error(
311→            `[session-manager] Low frame count: ${session.streamRecorder.frames} frames for ${duration.toFixed(1)}s ` +
312→              `(expected >= ${expectedMin}, dropped: ${session.streamRecorder.dropped})`
313→          );
314→        }
315→      }
316→
317→      // --- Stop avfoundation/x11grab recorder ---
318→      if (session.ffmpegRecorder.isCapturing()) {
319→        try {
320→          await session.ffmpegRecorder.stopCapture();
321→        } catch (err) {
322→          console.error("[session-manager] ffmpeg capture stop failed:", err);
323→          session.rawCapturePath = null;
324→          if (session.state.events.length === 0) throw err;
325→        }
326→      }
327→
328→      // --- Detect actual raw video dimensions via ffprobe ---
329→      if (session.rawCapturePath) {
330→        const probed = await probeVideoDimensions(session.rawCapturePath);
331→        if (probed) {
332→          actualSourceSize = probed;
333→          console.error(
334→            `[session-manager] Probed raw video: ${probed.width}x${probed.height}`
335→          );
336→        } else {
337→          const detected = session.streamRecorder?.detectedFrameSize;
338→          if (detected) {
339→            actualSourceSize = detected;
340→            console.error(
341→              `[session-manager] ffprobe failed, using stream metadata: ${detected.width}x${detected.height}`
342→            );
343→          }
344→        }
345→      }
346→
347→      // --- Post-process: canvas-based rendering with cursor, zoom, effects ---
348→      if (session.rawCapturePath) {
349→        try {
350→          const { renderVideo } = await import("../renderer/video-renderer.js");
351→
352→          const result = await renderVideo({
353→            rawVideoPath: session.rawCapturePath,
354→            events: session.state.events,
355→            sourceSize: actualSourceSize,
356→            outputSize: config.outputSize,
357→            outputPath: config.outputPath,
358→            outputFps: Math.min(config.fps, 30),
359→            speedRamp: true,
360→          });
361→
362→          videoProduced = true;
363→          console.error(
364→            `[session-manager] Render: ${result.frameCount} frames, ` +
365→              `${result.durationSec.toFixed(1)}s, canvas=${result.canvasRendered}`
366→          );
367→        } catch (err) {
368→          console.error(`[session-manager] Video render failed: ${err}`);
369→        }
370→
371→        // Clean up raw capture file
372→        await session.ffmpegRecorder.cleanup();
373→      }
374→
375→      session.state.status = "done";
376→      if (videoProduced) {
377→        session.state.outputPath = config.outputPath;
378→      }
379→
380→      return {
381→        outputPath: videoProduced ? config.outputPath : "",
382→        duration,
383→        eventCount: session.state.events.length,
384→        chapterCount: session.state.chapters.length,
385→      };
386→    } catch (err) {
387→      session.state.status = "error";
388→      session.state.error = err instanceof Error ? err.message : String(err);
389→      throw err;
390→    }
391→  }
392→
393→  /**
394→   * Get the current status of a session.
395→   */
396→  status(sessionId: string): {
397→    status: RecordingStatus;
398→    duration: number;
399→    eventCount: number;
400→    chapterCount: number;
401→    frameCount: number;
402→    droppedFrames: number;
403→    outputPath?: string;
404→  } {
405→    const session = this.getSession(sessionId);
406→    const endTime = session.state.endTime ?? Date.now();
407→    return {
408→      status: session.state.status,
409→      duration: (endTime - session.state.startTime) / 1000,
410→      eventCount: session.state.events.length,
411→      chapterCount: session.state.chapters.length,
412→      frameCount: session.streamRecorder?.frames ?? 0,
413→      droppedFrames: session.streamRecorder?.dropped ?? 0,
414→      outputPath: session.state.outputPath,
415→    };
416→  }
417→
418→  /**
419→   * Clean up a session — remove temp files and free resources.
420→   */
421→  async cleanup(sessionId: string): Promise<void> {
422→    const session = this.sessions.get(sessionId);
423→    if (!session) return;
424→
425→    session.ffmpegRecorder.kill();
426→    session.streamRecorder?.kill();
427→    await session.ffmpegRecorder.cleanup();
428→    this.sessions.delete(sessionId);
429→  }
430→
431→  /**
432→   * Stop all active sessions and clean up.
433→   */
434→  async shutdownAll(): Promise<void> {
435→    const ids = [...this.sessions.keys()];
436→    for (const id of ids) {
437→      const session = this.sessions.get(id);
438→      if (session && session.state.status === "recording") {
439→        try {
440→          await this.stop(id);
441→        } catch {
442→          // Best-effort during shutdown
443→        }
444→      }
445→      await this.cleanup(id);
446→    }
447→  }
448→
449→  /**
450→   * Resolve "auto" capture method.
451→   *
452→   * Uses agent-browser's WebSocket stream — captures JPEG frames of the
453→   * browser page only (not the app UI). No OS permission, no CDP conflicts.
454→   * Falls back to events-only if stream port not configured.
455→   *
456→   * Other methods (avfoundation, x11grab) available via explicit
457→   * captureMethod for standalone/external use.
458→   */
459→  private async resolveAutoCapture(): Promise<"stream" | "none"> {
460→    const streamPort = this.resolveStreamPort();
461→    if (streamPort) {
462→      return "stream";
463→    }
464→    return "none";
465→  }
466→
467→  /**
468→   * Resolve the agent-browser stream port.
469→   * Default: 9223. Override via AGENT_BROWSER_STREAM_PORT env var.
470→   */
471→  private resolveStreamPort(): number | null {
472→    // 1. Explicit env var (set by agent-browser-client.ts or manually)
473→    const envPort = process.env.AGENT_BROWSER_STREAM_PORT;
474→    if (envPort) {
475→      const port = parseInt(envPort, 10);
476→      if (!isNaN(port) && port > 0 && port < 65536) {
477→        return port;
478→      }
479→    }
480→
481→    // 2. Default port (matches STREAM_PORT in agent-browser-client.ts)
482→    return 9223;
483→  }
484→
485→  private getSession(sessionId: string): InternalSession {
486→    const session = this.sessions.get(sessionId);
487→    if (!session) {
488→      throw new Error(`Session not found: ${sessionId}`);
489→    }
490→    return session;
491→  }
492→}
