 79→const performanceState = {
 80→  fcp: null as number | null,
 81→  lcp: null as number | null,
 82→  cls: 0,
 83→  interactionDurations: new Map<number, number>(),
 84→  loafEntries: [] as LoafEntry[],
 85→};
 86→
 87→const THRESHOLDS: Record<string, [number, number]> = {
 88→  FCP: [FCP_GOOD_MS, FCP_POOR_MS],
 89→  LCP: [LCP_GOOD_MS, LCP_POOR_MS],
 90→  CLS: [CLS_GOOD, CLS_POOR],
 91→  INP: [INP_GOOD_MS, INP_POOR_MS],
 92→};
 93→
 94→const ratePerformanceMetric = (name: string, value: number): string => {
 95→  const threshold = THRESHOLDS[name];
 96→  if (!threshold) return "unknown";
 97→  if (value < threshold[0]) return "good";
 98→  if (value < threshold[1]) return "needs-improvement";
 99→  return "poor";
100→};
101→
102→try {
103→  new PerformanceObserver((list) => {
104→    for (const entry of list.getEntries()) {
105→      if (entry.name === "first-contentful-paint") {
106→        performanceState.fcp = entry.startTime;
107→      }
108→    }
109→  }).observe({ type: "paint", buffered: true });
110→} catch {}
111→
112→try {
113→  new PerformanceObserver((list) => {
114→    for (const entry of list.getEntries()) {
115→      performanceState.lcp = entry.startTime;
116→    }
117→  }).observe({ type: "largest-contentful-paint", buffered: true });
118→} catch {}
119→
120→try {
121→  new PerformanceObserver((list) => {
122→    for (const entry of list.getEntries()) {
123→      const { interactionId } = entry as EventTimingEntry;
124→      if (interactionId && interactionId > 0) {
125→        const current = performanceState.interactionDurations.get(interactionId) ?? 0;
126→        performanceState.interactionDurations.set(interactionId, Math.max(current, entry.duration));
127→      }
128→    }
129→  }).observe({
130→    type: "event",
131→    buffered: true,
132→    durationThreshold: INP_DURATION_THRESHOLD_MS,
133→  } as PerformanceObserverInit);
134→} catch {}
135→
136→try {
137→  const sessionEntries: LayoutShiftEntry[] = [];
138→  new PerformanceObserver((list) => {
139→    for (const entry of list.getEntries()) {
140→      const shiftEntry = entry as LayoutShiftEntry;
141→      if (shiftEntry.hadRecentInput) continue;
142→      sessionEntries.push(shiftEntry);
143→    }
144→    let maxSessionValue = 0;
145→    let currentSessionValue = 0;
146→    let currentSessionStart = 0;
147→    let previousEntryEnd = 0;
148→    for (const entry of sessionEntries) {
149→      if (
150→        entry.startTime - previousEntryEnd > CLS_SESSION_GAP_MS ||
151→        entry.startTime - currentSessionStart > CLS_SESSION_CAP_MS
152→      ) {
153→        currentSessionValue = 0;
154→        currentSessionStart = entry.startTime;
155→      }
156→      currentSessionValue += entry.value;
157→      previousEntryEnd = entry.startTime + entry.duration;
158→      if (currentSessionValue > maxSessionValue) {
159→        maxSessionValue = currentSessionValue;
160→      }
161→    }
162→    performanceState.cls = maxSessionValue;
163→  }).observe({ type: "layout-shift", buffered: true });
164→} catch {}
165→
166→try {
167→  if (
168→    typeof PerformanceObserver !== "undefined" &&
169→    PerformanceObserver.supportedEntryTypes.includes("long-animation-frame")
170→  ) {
171→    new PerformanceObserver((list) => {
172→      for (const entry of list.getEntries()) {
173→        const loaf = entry as unknown as LoafEntry & { scripts: LoafScript[] };
174→        performanceState.loafEntries.push({
175→          startTime: loaf.startTime,
176→          duration: loaf.duration,
177→          blockingDuration: loaf.blockingDuration,
178→          renderStart: loaf.renderStart,
179→          styleAndLayoutStart: loaf.styleAndLayoutStart,
180→          firstUIEventTimestamp: loaf.firstUIEventTimestamp,
181→          scripts: loaf.scripts.map((script) => ({
182→            invokerType: script.invokerType,
183→            invoker: script.invoker,
184→            sourceURL: script.sourceURL,
185→            sourceFunctionName: script.sourceFunctionName,
186→            sourceCharPosition: script.sourceCharPosition,
187→            duration: script.duration,
188→            forcedStyleAndLayoutDuration: script.forcedStyleAndLayoutDuration,
189→          })),
190→        });
191→        if (performanceState.loafEntries.length > LOAF_BUFFER_LIMIT) {
192→          performanceState.loafEntries.shift();
193→        }
194→      }
195→    }).observe({ type: "long-animation-frame", buffered: true });
196→  }
197→} catch {}
198→
199→const buildMetric = (name: string, value: number | null): PerformanceMetricEntry | null => {
200→  if (value === null) return null;
201→  const rounded =
202→    name === "CLS"
203→      ? Math.round(value * CLS_PRECISION_FACTOR) / CLS_PRECISION_FACTOR
204→      : Math.round(value);
205→  return { value: rounded, rating: ratePerformanceMetric(name, value) };
206→};
207→
208→export const getPerformanceMetrics = (): PerformanceMetricsResult => {
209→  const { fcp, lcp, cls, interactionDurations } = performanceState;
210→
211→  let inp: number | null = null;
212→  if (interactionDurations.size > 0) {
213→    const durations = [...interactionDurations.values()].sort((a, b) => b - a);
214→    inp = durations[0];
215→  }
216→
217→  return {
218→    fcp: buildMetric("FCP", fcp),
219→    lcp: buildMetric("LCP", lcp),
220→    cls: buildMetric("CLS", cls),
221→    inp: buildMetric("INP", inp),
222→  };
223→};
