225→export interface PerformanceTrace {
226→  webVitals: PerformanceMetricsResult;
227→  navigation: NavigationEntry | null;
228→  longAnimationFrames: LoafEntry[];
229→  resources: {
230→    totalCount: number;
231→    totalTransferSizeBytes: number;
232→    slowest: ResourceEntry[];
233→    largest: ResourceEntry[];
234→  };
235→}
236→
237→export const getPerformanceTrace = (): PerformanceTrace => {
238→  const webVitals = getPerformanceMetrics();
239→
240→  let navigation: NavigationEntry | null = null;
241→  try {
242→    const navEntries = performance.getEntriesByType("navigation");
243→    if (navEntries.length > 0) {
244→      const nav = navEntries[0] as PerformanceNavigationTiming;
245→      navigation = {
246→        ttfb: Math.round(nav.responseStart - nav.requestStart),
247→        domContentLoaded: Math.round(nav.domContentLoadedEventEnd - nav.startTime),
248→        loadComplete: Math.round(nav.loadEventEnd - nav.startTime),
249→        redirectDuration: Math.round(nav.redirectEnd - nav.redirectStart),
250→        serverTiming: (nav.serverTiming ?? []).map((entry) => ({
251→          name: entry.name,
252→          duration: entry.duration,
253→          description: entry.description,
254→        })),
255→      };
256→    }
257→  } catch {}
258→
259→  let resources: PerformanceTrace["resources"] = {
260→    totalCount: 0,
261→    totalTransferSizeBytes: 0,
262→    slowest: [],
263→    largest: [],
264→  };
265→  try {
266→    const resourceEntries = performance.getEntriesByType("resource") as PerformanceResourceTiming[];
267→    const mapped: ResourceEntry[] = resourceEntries.map((entry) => ({
268→      name: entry.name,
269→      initiatorType: entry.initiatorType,
270→      transferSize: entry.transferSize,
271→      duration: Math.round(entry.duration),
272→    }));
273→
274→    const totalTransferSizeBytes = mapped.reduce((sum, entry) => sum + entry.transferSize, 0);
275→
276→    const slowest = [...mapped]
277→      .sort((left, right) => right.duration - left.duration)
278→      .slice(0, RESOURCE_TOP_N);
279→    const largest = [...mapped]
280→      .sort((left, right) => right.transferSize - left.transferSize)
281→      .slice(0, RESOURCE_TOP_N);
282→
283→    resources = {
284→      totalCount: mapped.length,
285→      totalTransferSizeBytes,
286→      slowest,
287→      largest,
288→    };
289→  } catch {}
290→
291→  return {
292→    webVitals,
293→    navigation,
294→    longAnimationFrames: [...performanceState.loafEntries],
295→    resources,
296→  };
297→};
