345→export const findCursorInteractiveElements = (
346→  rootSelector: string,
347→  maxTextLength: number,
348→  interactiveRoles: string[],
349→  interactiveTags: string[],
350→  maxResults: number,
351→): CursorInteractiveResult[] => {
352→  const interactiveRoleSet = new Set(interactiveRoles);
353→  const interactiveTagSet = new Set(interactiveTags);
354→  const root = document.querySelector(rootSelector) || document.body;
355→  const elements = root.querySelectorAll("*");
356→  const results: CursorInteractiveResult[] = [];
357→
358→  for (const element of elements) {
359→    const tagName = element.tagName.toLowerCase();
360→    if (interactiveTagSet.has(tagName)) continue;
361→
362→    const role = element.getAttribute("role");
363→    if (role && interactiveRoleSet.has(role.toLowerCase())) continue;
364→
365→    const computedStyle = getComputedStyle(element);
366→    const hasCursorPointer = computedStyle.cursor === "pointer";
367→    const hasOnClick =
368→      element.hasAttribute("onclick") ||
369→      (element instanceof HTMLElement && element.onclick !== null);
370→    const tabIndexAttr = element.getAttribute("tabindex");
371→    const hasTabIndex = tabIndexAttr !== null && tabIndexAttr !== "-1";
372→
373→    if (!hasCursorPointer && !hasOnClick && !hasTabIndex) continue;
374→
375→    if (hasCursorPointer && !hasOnClick && !hasTabIndex) {
376→      const parent = element.parentElement;
377→      if (parent && getComputedStyle(parent).cursor === "pointer") continue;
378→    }
379→
380→    const text = (element.textContent || "").trim().slice(0, maxTextLength);
381→    if (!text) continue;
382→
383→    const rect = element.getBoundingClientRect();
384→    if (rect.width === 0 || rect.height === 0) continue;
385→
386→    const reasons: string[] = [];
387→    if (hasCursorPointer) reasons.push("cursor:pointer");
388→    if (hasOnClick) reasons.push("onclick");
389→    if (hasTabIndex) reasons.push("tabindex");
390→
391→    results.push({
392→      selector: finder(element, { root }),
393→      text,
394→      reason: reasons.join(", "),
395→    });
396→
397→    if (results.length >= maxResults) break;
398→  }
399→
400→  return results;
401→};
