 54→export const startLiveViewServer = Effect.fn("LiveViewServer.start")(function* (
 55→  options: StartLiveViewServerOptions,
 56→) {
 57→  const parsedUrl = new URL(options.liveViewUrl);
 58→  const sseClients = new Set<SseClient>();
 59→  const accumulatedReplayEvents: eventWithTime[] = [];
 60→  let latestRunState: ViewerRunState | undefined;
 61→
 62→  const stepsPubSub = yield* PubSub.unbounded<ViewerRunState>();
 63→
 64→  const viewerHtml = buildReplayViewerHtml({
 65→    title: "Expect Live View",
 66→    eventsSource: "sse",
 67→  });
