 97→  const handleSseRequest = (request: IncomingMessage, response: SseClient): void => {
 98→    response.writeHead(200, {
 99→      "Content-Type": "text/event-stream",
100→      Connection: "keep-alive",
101→      ...CORS_HEADERS,
102→      ...NO_CACHE_HEADERS,
103→    });
104→    response.flushHeaders();
105→    sseClients.add(response);
106→    request.on("close", () => sseClients.delete(response));
107→  };
108→
109→  const handleStepsPost = (request: IncomingMessage, response: SseClient): void => {
110→    const chunks: Buffer[] = [];
111→    request.on("data", (chunk: Buffer) => chunks.push(chunk));
112→    request.on("end", () => {
113→      try {
114→        const body = Buffer.concat(chunks).toString("utf-8");
115→        const parsed: unknown = JSON.parse(body);
116→        if (!isViewerRunState(parsed)) {
117→          response.writeHead(400, {
118→            "Content-Type": "text/plain",
119→            ...CORS_HEADERS,
120→            ...NO_CACHE_HEADERS,
121→          });
122→          response.end("Invalid step state: missing status or steps");
123→          return;
124→        }
125→        broadcastRunState(parsed);
126→        response.writeHead(204, { ...CORS_HEADERS, ...NO_CACHE_HEADERS });
127→        response.end();
128→      } catch {
129→        response.writeHead(400, {
130→          "Content-Type": "text/plain",
131→          ...CORS_HEADERS,
132→          ...NO_CACHE_HEADERS,
133→        });
134→        response.end("Invalid JSON");
135→      }
136→    });
137→  };
138→
139→  const routeRequest = (request: IncomingMessage, response: SseClient): void => {
140→    if (request.method === "OPTIONS") {
141→      response.writeHead(204, CORS_HEADERS);
142→      response.end();
143→      return;
144→    }
145→
146→    const pathname = new URL(request.url ?? "/", parsedUrl).pathname;
147→
148→    if (pathname === "/") {
149→      response.writeHead(200, {
150→        "Content-Type": "text/html; charset=utf-8",
151→        ...CORS_HEADERS,
152→        ...NO_CACHE_HEADERS,
153→      });
154→      response.end(viewerHtml);
155→      return;
156→    }
157→
158→    if (pathname === "/events") {
159→      handleSseRequest(request, response);
160→      return;
161→    }
162→
163→    if (pathname === "/latest.json") {
164→      const body = JSON.stringify(accumulatedReplayEvents);
165→      response.writeHead(200, {
166→        "Content-Type": "application/json",
167→        "Content-Length": Buffer.byteLength(body),
168→        ...CORS_HEADERS,
169→        ...NO_CACHE_HEADERS,
170→      });
171→      response.end(body);
172→      return;
173→    }
174→
175→    if (pathname === "/steps") {
176→      if (request.method === "POST") {
177→        handleStepsPost(request, response);
178→        return;
179→      }
180→      const body = JSON.stringify(latestRunState ?? { title: "", status: "running", steps: [] });
181→      response.writeHead(200, {
182→        "Content-Type": "application/json",
183→        "Content-Length": Buffer.byteLength(body),
184→        ...CORS_HEADERS,
185→        ...NO_CACHE_HEADERS,
186→      });
187→      response.end(body);
188→      return;
189→    }
190→
191→    response.writeHead(404, {
192→      "Content-Type": "text/plain; charset=utf-8",
193→      ...CORS_HEADERS,
194→      ...NO_CACHE_HEADERS,
195→    });
196→    response.end("Not found");
197→  };
198→
199→  const server = createServer(routeRequest);
200→
201→  yield* listenServer(server, parsedUrl.hostname, Number(parsedUrl.port));
202→
203→  const pollPage = Effect.sync(() => options.getPage()).pipe(
204→    Effect.flatMap((page) => {
205→      if (!page || page.isClosed()) return Effect.void;
206→      return evaluateRuntime(page, "startRecording").pipe(
207→        Effect.catchCause(() => Effect.void),
208→        Effect.flatMap(() => evaluateRuntime(page, "getEvents")),
209→        Effect.tap((events) =>
210→          Effect.sync(() => {
211→            if (Array.isArray(events) && events.length > 0) {
212→              broadcastReplayEvents(events);
213→            }
214→          }),
215→        ),
216→        Effect.catchCause((cause) => Effect.logDebug("Replay event collection failed", { cause })),
217→      );
218→    }),
219→  );
220→
221→  const replayPollFiber = yield* pollPage.pipe(
222→    Effect.repeat(Schedule.spaced(EVENT_COLLECT_INTERVAL_MS)),
223→    Effect.forkDetach,
224→  );
225→
226→  const stepsBroadcastFiber = yield* Stream.fromPubSub(stepsPubSub).pipe(
227→    Stream.tap((state) => Effect.sync(() => broadcastRunState(state))),
228→    Stream.runDrain,
229→    Effect.forkDetach,
230→  );
231→
232→  return {
233→    url: parsedUrl.toString(),
234→    pushRunState: (state: ViewerRunState) => {
235→      PubSub.publishUnsafe(stepsPubSub, state);
236→    },
237→    getLatestRunState: () => latestRunState,
238→    close: Effect.gen(function* () {
239→      yield* Fiber.interrupt(replayPollFiber);
240→      yield* Fiber.interrupt(stepsBroadcastFiber);
241→      for (const client of sseClients) client.end();
242→      sseClients.clear();
243→      yield* closeServer(server);
244→    }),
245→  } satisfies LiveViewHandle;
246→});
