 42→interface ConsoleEntry {
 43→  readonly type: string;
 44→  readonly text: string;
 45→  readonly timestamp: number;
 46→}
 47→
 48→interface NetworkEntry {
 49→  readonly url: string;
 50→  readonly method: string;
 51→  status: number | undefined;
 52→  readonly resourceType: string;
 53→  readonly timestamp: number;
 54→}
 55→
 56→export interface BrowserSessionData {
 57→  readonly browser: PlaywrightBrowser;
 58→  readonly context: BrowserContext;
 59→  readonly page: Page;
 60→  readonly consoleMessages: ConsoleEntry[];
 61→  readonly networkRequests: NetworkEntry[];
 62→  readonly replayOutputPath: string | undefined;
 63→  readonly accumulatedReplayEvents: eventWithTime[];
 64→  readonly trackedPages: Set<Page>;
 65→  lastSnapshot: SnapshotResult | undefined;
 66→}
