 70→  cookies?: boolean;
 71→  waitUntil?: "load" | "domcontentloaded" | "networkidle" | "commit";
 72→  cdpUrl?: string;
 73→}
 74→
 75→export interface OpenResult {
 76→  readonly injectedCookieCount: number;
 77→}
 78→
 79→export interface CloseResult {
 80→  readonly replaySessionPath: string | undefined;
 81→  readonly reportPath: string | undefined;
 82→  readonly videoPath: string | undefined;
 83→  readonly tmpReplaySessionPath: string | undefined;
 84→  readonly tmpReportPath: string | undefined;
 85→  readonly tmpVideoPath: string | undefined;
