 20→const buildLoadEventsScript = (source: EventsSource): string => {
 21→  if (source === "sse") {
 22→    return `
 23→      const res = await fetch('/latest.json');
 24→      if (res.ok) { allEvents = await res.json(); if (allEvents.length >= 2) initPlayer(allEvents); }
 25→      const es = new EventSource('/events');
 26→      es.addEventListener('replay', (msg) => { try { for (const e of JSON.parse(msg.data)) { allEvents.push(e); if (player) player.getReplayer().addEvent(e); } if (!player && allEvents.length >= 2) initPlayer(allEvents); } catch {} });
 27→      es.addEventListener('steps', (msg) => { try { updateSteps(JSON.parse(msg.data)); } catch {} });
 28→      es.onerror = () => { if (statusEl) statusEl.textContent = 'Connection lost. Retrying...'; };`;
 29→  }
 30→
 31→  const escapedPath = source.ndjsonPath.replaceAll("'", "\\'");
 32→  return `
 33→      if (window.__EXPECT_REPLAY_NDJSON__) {
 34→        allEvents = window.__EXPECT_REPLAY_NDJSON__.trim().split('\\n').map(l => JSON.parse(l));
 35→        if (allEvents.length >= 2) initPlayer(allEvents);
 36→        else if (statusEl) statusEl.textContent = 'No replay events recorded.';
 37→      } else {
 38→        const res = await fetch('${escapedPath}');
 39→        if (res.ok) {
 40→          allEvents = (await res.text()).trim().split('\\n').map(l => JSON.parse(l));
 41→          if (allEvents.length >= 2) initPlayer(allEvents);
 42→          else if (statusEl) statusEl.textContent = 'No replay events recorded.';
 43→        } else if (statusEl) statusEl.textContent = 'Failed to load replay.';
 44→      }`;
