 49→  return `
 50→    const stepsPanel = document.getElementById('steps-panel');
 51→    const runTitle = document.getElementById('run-title');
 52→    const runStatus = document.getElementById('run-status');
 53→    const runSummary = document.getElementById('run-summary');
 54→    const stepsList = document.getElementById('steps-list');
 55→    let initialSteps = ${initialData};
 56→    if (initialSteps) updateSteps(initialSteps);
 57→
 58→    function updateSteps(state) {
 59→      if (!stepsPanel || !state) return;
 60→      stepsPanel.style.display = 'block';
 61→      if (runTitle) runTitle.textContent = state.title || 'Test Run';
 62→      if (runStatus) {
 63→        runStatus.textContent = state.status;
 64→        runStatus.className = 'run-status status-' + state.status;
 65→      }
 66→      if (runSummary) {
 67→        runSummary.textContent = state.summary || '';
 68→        runSummary.style.display = state.summary ? 'block' : 'none';
 69→      }
 70→      if (stepsList && state.steps) {
 71→        stepsList.innerHTML = '';
 72→        for (const step of state.steps) {
 73→          const li = document.createElement('li');
 74→          li.className = 'step-item step-' + step.status;
 75→          const badge = document.createElement('span');
 76→          badge.className = 'step-badge';
 77→          badge.textContent = step.status === 'passed' ? '\\u2713'
 78→            : step.status === 'failed' ? '\\u2717'
 79→            : step.status === 'active' ? '\\u25CF'
 80→            : '\\u25CB';
 81→          const title = document.createElement('span');
 82→          title.className = 'step-title';
