   1→// Browser automation tools powered by agent-browser CLI.
   2→// Each tool executes agent-browser commands via CDP (Chrome DevTools Protocol).
   3→// The daemon auto-starts on first use per session.
   4→//
   5→// Key features:
   6→// - Coordinate return: click/type/hover return element bounding boxes for screen recording
   7→// - Batch mode: BrowserBatchActions executes multiple commands in one round-trip
   8→// - Snapshot filtering: interactive-only, compact, depth-limited, CSS-scoped
   9→// - Wait modes: text, networkIdle, elementVisible, elementGone
  10→
  11→import { tool } from "@anthropic-ai/claude-agent-sdk";
  12→import type { SdkMcpToolDefinition } from "@anthropic-ai/claude-agent-sdk";
  13→import { z } from "zod";
  14→import { writeFileSync, mkdirSync, existsSync, readFileSync, unlinkSync } from "fs";
  15→import { join } from "path";
  16→import { homedir, tmpdir } from "os";
  17→import { getErrorMessage } from "@shared/lib/errors";
  18→import {
  19→  execAgentBrowser,
  20→  execWithSnapshot,
  21→  executeBatch,
  22→  getSnapshot,
  23→  type ElementBox,
  24→} from "./agent-browser-client";
  25→
  26→// ============================================================================
  27→// Snapshot file-based fallback constants
  28→// ============================================================================
  29→
  30→const SNAPSHOT_SIZE_THRESHOLD = 25 * 1024; // 25 KB for action tools
  31→const SNAPSHOT_SIZE_THRESHOLD_LARGE = 200 * 1024; // 200 KB for BrowserSnapshot
  32→const PREVIEW_LINE_COUNT = 50;
  33→const BROWSER_LOGS_DIR = join(homedir(), ".deus", "browser-logs");
  34→
  35→// ============================================================================
  36→// Shared response helpers
  37→// ============================================================================
  38→
  39→/** Wrap a tool handler with error catch for browser unavailability */
  40→function withBrowserTool<TArgs>(
  41→  fn: (args: TArgs) => Promise<{ content: Array<{ type: string; [key: string]: unknown }> }>
  42→): (args: TArgs) => Promise<{ content: Array<{ type: string; [key: string]: unknown }> }> {
  43→  return async (args: TArgs) => {
  44→    try {
  45→      return await fn(args);
  46→    } catch (err: unknown) {
  47→      return textResult(`Browser not available: ${getErrorMessage(err)}`);
  48→    }
  49→  };
  50→}
  51→
  52→/** Build a single-text-block tool result */
  53→function textResult(text: string): { content: [{ type: "text"; text: string }] } {
  54→  return { content: [{ type: "text", text }] };
  55→}
  56→
  57→/** Redact sensitive arguments (passwords, tokens) from batch action summaries */
  58→function summarizeBatchAction(action: string[]): string {
  59→  const [command, firstArg] = action;
  60→  if (command === "fill" || command === "type") {
  61→    return [command, firstArg ?? "<?>", "<redacted>"].join(" ");
  62→  }
  63→  return action.join(" ");
  64→}
  65→
  66→/**
  67→ * Format a snapshot response with file-based fallback for large snapshots.
  68→ * Optionally includes element bounding box for screen recording.
  69→ */
  70→function formatSnapshotResponse(
  71→  action: string,
  72→  snapshot: string | undefined,
  73→  pageUrl?: string,
  74→  pageTitle?: string,
  75→  detailLines?: string[],
  76→  sizeThreshold: number = SNAPSHOT_SIZE_THRESHOLD,
  77→  elementBox?: ElementBox | null
  78→): string {
  79→  const sections: string[] = [];
  80→
  81→  sections.push(`### Action: ${action}`);
  82→  if (detailLines && detailLines.length > 0) {
  83→    for (const line of detailLines) {
  84→      sections.push(`- ${line}`);
  85→    }
  86→  }
  87→
  88→  if (elementBox) {
  89→    const cx = Math.round(elementBox.x + elementBox.width / 2);
  90→    const cy = Math.round(elementBox.y + elementBox.height / 2);
  91→    sections.push("");
  92→    sections.push("### Element");
  93→    sections.push(
  94→      `- Bounding box: x=${Math.round(elementBox.x)} y=${Math.round(elementBox.y)} w=${Math.round(elementBox.width)} h=${Math.round(elementBox.height)}`
  95→    );
  96→    sections.push(`- Center: (${cx}, ${cy})`);
  97→  }
  98→
  99→  sections.push("");
 100→  sections.push("### Page state");
 101→  if (pageUrl) sections.push(`- Page URL: ${pageUrl}`);
 102→  if (pageTitle) sections.push(`- Page Title: ${pageTitle}`);
 103→
 104→  if (!snapshot) {
 105→    sections.push("- Page Snapshot: (not available)");
 106→    return sections.join("\n");
 107→  }
 108→
 109→  const snapshotBytes = Buffer.byteLength(snapshot, "utf-8");
 110→  const snapshotLines = snapshot.split("\n");
 111→
 112→  if (snapshotBytes <= sizeThreshold) {
 113→    sections.push(`- Page Snapshot (${snapshotLines.length} lines)`);
 114→    sections.push("");
 115→    sections.push(snapshot);
 116→  } else {
 117→    let filePath: string | null = null;
 118→    try {
 119→      if (!existsSync(BROWSER_LOGS_DIR)) {
 120→        mkdirSync(BROWSER_LOGS_DIR, { recursive: true });
 121→      }
 122→      const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
 123→      filePath = join(BROWSER_LOGS_DIR, `snapshot-${timestamp}.log`);
 124→      writeFileSync(filePath, snapshot, "utf-8");
 125→    } catch (err: unknown) {
 126→      console.warn(`[browser] Failed to write snapshot file: ${getErrorMessage(err)}`);
 127→    }
 128→
 129→    if (filePath) {
 130→      sections.push(
 131→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) written to file`
 132→      );
 133→      sections.push(`- Snapshot File: ${filePath}`);
 134→      sections.push(`- Preview (first ${PREVIEW_LINE_COUNT} lines):`);
 135→      sections.push("");
 136→      sections.push(snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n"));
 137→    } else {
 138→      sections.push(
 139→        `- Page Snapshot: Large snapshot (${snapshotBytes} bytes, ${snapshotLines.length} lines) — truncated inline`
 140→      );
 141→      sections.push("");
 142→      sections.push(snapshotLines.slice(0, PREVIEW_LINE_COUNT).join("\n"));
 143→    }
 144→
 145→    const remaining = snapshotLines.length - PREVIEW_LINE_COUNT;
 146→    if (remaining > 0) {
 147→      sections.push("");
 148→      sections.push(
 149→        filePath
 150→          ? `... (${remaining} more lines in file)`
 151→          : `... (${remaining} more lines truncated)`
 152→      );
 153→    }
 154→  }
 155→
 156→  return sections.join("\n");
 157→}
 158→
 159→/** Structured data emitted after each browser tool execution for recording. */
 160→export interface BrowserToolAction {
 161→  toolName: string;
 162→  elementBox?: ElementBox | null;
 163→  url?: string;
 164→  text?: string;
 165→  scrollDirection?: string;
 166→}
 167→
 168→/** Callback type for the recording bridge to snoop on browser tool executions. */
 169→export type OnBrowserAction = (action: BrowserToolAction) => void;
 170→
 171→/**
 172→ * Creates the browser automation tool definitions for a given session.
 173→ * @param onAction Optional callback fired after each successful browser tool
 174→ *   execution with structured data for the recording bridge.
 175→ */
 176→export function createBrowserTools(
 177→  sessionId: string,
 178→  onAction?: OnBrowserAction
 179→): SdkMcpToolDefinition<any>[] {
 180→  return [
 181→    tool(
 182→      "BrowserSnapshot",
 183→      `Capture an accessibility snapshot of the current browser page. Returns a YAML-formatted tree with element roles, names, and reference IDs (@e1, @e2).
 184→
 185→Use ref IDs to target elements with BrowserClick, BrowserType, BrowserHover, BrowserSelectOption.
 186→
 187→Options:
 188→- filter: "interactive" shows only buttons/links/inputs (recommended for most tasks). "compact" removes empty structural nodes. "all" (default) shows full tree.
 189→- depth: Limit nesting depth (e.g., 3 for shallow pages).
 190→- selector: CSS selector to scope the snapshot (e.g., "#main", ".form-container").
 191→
 192→For large pages, the snapshot is saved to a file and a preview is returned.`,
 193→      {
 194→        filter: z
 195→          .enum(["all", "interactive", "compact"])
 196→          .optional()
 197→          .describe(
 198→            "Filter mode: 'interactive' shows only actionable elements, 'compact' removes empty nodes, 'all' shows full tree (default)"
 199→          ),
 200→        depth: z.number().optional().describe("Limit tree depth to N levels"),
 201→        selector: z
 202→          .string()
 203→          .optional()
 204→          .describe("CSS selector to scope snapshot to a subtree (e.g., '#main')"),
 205→      },
 206→      withBrowserTool(
 207→        async (args) => {
 208→          const response = await getSnapshot(sessionId, 20_000, {
 209→            interactive: args.filter === "interactive",
 210→            compact: args.filter === "compact",
 211→            depth: args.depth,
 212→            selector: args.selector,
 213→          });
 214→
 215→          if (response.error) {
 216→            return textResult(`Error capturing snapshot: ${response.error}`);
 217→          }
 218→
 219→          return textResult(
 220→            formatSnapshotResponse(
 221→              "snapshot",
 222→              response.snapshot,
 223→              response.url,
 224→              response.title,
 225→              args.filter ? [`Filter: ${args.filter}`] : undefined,
 226→              SNAPSHOT_SIZE_THRESHOLD_LARGE
 227→            )
 228→          );
 229→        }
 230→      )
 231→    ),
 232→
 233→    tool(
 234→      "BrowserClick",
 235→      `Click on a web page element by reference ID or coordinates.
 236→
