  1→// Thin wrapper around the agent-browser CLI.
  2→// Executes commands via child_process and parses JSON responses.
  3→// The daemon auto-starts on the first command per session and maintains
  4→// browser state (refs, cookies, DOM) across calls.
  5→//
  6→// CDP SAFETY: agent-browser connects to Chrome DevTools Protocol to control
  7→// the browser. In Electron, CDP port 19222 exposes ALL page targets including
  8→// the renderer (localhost:1420). If agent-browser gets the raw port, it will
  9→// discover and navigate the renderer → ENTIRE APP UI REPLACED.
 10→//
 11→// Fix: getCdpWsUrl() finds the specific BrowserView's WebSocket URL and
 12→// passes that to --cdp instead of the port. If no BrowserView exists,
 13→// we omit --cdp entirely so agent-browser launches its own browser.
 14→// NEVER pass --cdp PORT_NUMBER — always use the specific WS URL.
 15→
 16→import { execFile, spawn } from "child_process";
 17→import { dirname, join } from "path";
 18→
 19→export interface AgentBrowserResult {
 20→  success: boolean;
 21→  data: Record<string, unknown> | null;
 22→  error: string | null;
 23→}
 24→
 25→export interface ElementBox {
 26→  x: number;
 27→  y: number;
 28→  width: number;
 29→  height: number;
 30→}
 31→
 32→// Resolve the binary once at module load.
 33→// The npm package has a Node.js wrapper at bin/agent-browser.js that selects
 34→// the correct platform binary. We resolve it relative to the package directory
 35→// since the package has no "main" field (require.resolve would throw).
 36→// Note: agent-server is bundled to CJS, so require.resolve is available.
 37→const BINARY = (() => {
 38→  try {
 39→    const pkgDir = dirname(require.resolve("agent-browser/package.json"));
 40→    return join(pkgDir, "bin", "agent-browser.js");
 41→  } catch {
 42→    return "agent-browser"; // fallback to PATH
 43→  }
 44→})();
 45→
 46→const DEFAULT_TIMEOUT_MS = 35_000;
 47→
 48→/**
 49→ * When CDP_PORT is set (Electron desktop mode), agent-browser connects to the
 50→ * IDE's own BrowserView via Chrome DevTools Protocol instead of spawning a
 51→ * separate Chrome process. This means:
 52→ * - Agent and user see the same browser (shared cookies, real-time visibility)
 53→ * - No separate Chrome daemon to manage
 54→ * - `--cdp <ws-url>` is prepended to all agent-browser commands
 55→ *
 56→ * We pass the BrowserView's full WebSocket debugger URL (not just the port)
 57→ * so agent-browser connects directly to the managed BrowserView page.
 58→ * Without this, agent-browser would discover ALL page targets (including the
 59→ * Electron renderer at localhost:1420) and navigate the renderer away,
 60→ * destroying the app UI.
 61→ */
 62→const CDP_PORT = process.env.CDP_PORT;
 63→
 64→/** Cached WebSocket URL for the managed BrowserView target */
 65→let cachedCdpWsUrl: string | null = null;
 66→
 67→/**
 68→ * Find the managed BrowserView's CDP WebSocket URL.
 69→ * Queries the CDP /json endpoint and picks a page target that isn't
 70→ * the Electron renderer (localhost) or devtools.
 71→ */
 72→async function getCdpWsUrl(): Promise<string | null> {
 73→  if (!CDP_PORT) return null;
 74→  // Return cached URL if we have one
 75→  if (cachedCdpWsUrl) return cachedCdpWsUrl;
 76→
 77→  try {
 78→    const res = await fetch(`http://127.0.0.1:${CDP_PORT}/json`);
 79→    const targets = (await res.json()) as Array<{
 80→      type: string;
 81→      url?: string;
 82→      webSocketDebuggerUrl?: string;
 83→    }>;
 84→
 85→    // Find a page target that ISN'T the Electron renderer or devtools
 86→    const browserView = targets.find(
 87→      (t) =>
 88→        t.type === "page" &&
 89→        t.webSocketDebuggerUrl &&
 90→        !t.url?.startsWith("http://localhost:") &&
 91→        !t.url?.startsWith("http://127.0.0.1:") &&
 92→        !t.url?.startsWith("devtools://")
 93→    );
 94→
 95→    if (browserView?.webSocketDebuggerUrl) {
 96→      cachedCdpWsUrl = browserView.webSocketDebuggerUrl;
 97→      return cachedCdpWsUrl;
 98→    }
 99→  } catch {
100→    // CDP not available
101→  }
102→  return null;
103→}
104→
105→/** Invalidate cached CDP URL (call when BrowserView is recreated) */
106→export function invalidateCdpCache(): void {
107→  cachedCdpWsUrl = null;
108→}
109→
110→/** Build final args with CDP prefix — uses BrowserView's WS URL if available */
111→async function buildArgs(args: string[]): Promise<string[]> {
112→  if (!CDP_PORT) return args;
113→
114→  // Try to get the specific BrowserView's WS URL
115→  const wsUrl = await getCdpWsUrl();
116→  if (wsUrl) return ["--cdp", wsUrl, ...args];
117→
118→  // No BrowserView target found — do NOT fall back to just the port.
119→  // Passing --cdp 19222 causes agent-browser to discover ALL targets
120→  // including localhost:1420 (the Electron renderer) and navigate it,
121→  // replacing the entire app UI with the target page.
122→  // Instead, let agent-browser launch its own browser.
123→  return args;
124→}
125→
126→/**
127→ * Fixed stream port for agent-browser's WebSocket frame server.
128→ * Screen-studio's StreamRecorder connects here to capture frames for recording.
129→ * Hardcoded so both sides agree without manual env var configuration.
130→ */
131→const STREAM_PORT = "9223";
132→
133→/** Build env for agent-browser subprocess */
134→function buildEnv(sessionId: string): NodeJS.ProcessEnv {
135→  return {
136→    ...process.env,
137→    AGENT_BROWSER_SESSION: sessionId,
138→    AGENT_BROWSER_HEADED: "1",
139→    AGENT_BROWSER_STREAM_PORT: STREAM_PORT,
140→  };
141→}
142→
143→/** Parse the last JSON object from stdout (agent-browser may print status lines before JSON) */
144→function parseJsonFromOutput(output: string): AgentBrowserResult | null {
145→  if (!output) return null;
146→  const lines = output.split("\n");
147→  for (let i = lines.length - 1; i >= 0; i--) {
148→    const line = lines[i].trim();
149→    if (line.startsWith("{") || line.startsWith("[")) {
150→      try {
151→        const parsed = JSON.parse(line);
152→        if (Array.isArray(parsed)) {
153→          return { success: true, data: { results: parsed }, error: null };
154→        }
155→        const error =
156→          typeof parsed.error === "string" && parsed.error.length > 0 ? parsed.error : null;
157→        return {
158→          success: parsed.success === false ? false : error == null,
159→          data: parsed.data ?? parsed,
160→          error,
161→        };
162→      } catch {
163→        continue;
164→      }
165→    }
166→  }
167→  return null;
168→}
169→
170→/**
171→ * Execute an agent-browser command for a given session.
172→ */
173→export async function execAgentBrowser(
174→  sessionId: string,
175→  args: string[],
176→  timeoutMs = DEFAULT_TIMEOUT_MS
177→): Promise<AgentBrowserResult> {
178→  const finalArgs = await buildArgs(args);
179→  const env = buildEnv(sessionId);
180→
181→  return new Promise<AgentBrowserResult>((resolve, reject) => {
182→    const child = execFile(
183→      BINARY,
184→      finalArgs,
185→      { env, timeout: timeoutMs, maxBuffer: 10 * 1024 * 1024 },
186→      (error, stdout, stderr) => {
187→        const output = stdout.trim();
188→        const parsed = parseJsonFromOutput(output);
189→        if (parsed) {
190→          resolve(parsed);
191→          return;
192→        }
193→
194→        if (error) {
195→          resolve({
196→            success: false,
197→            data: output ? { text: output } : null,
198→            error: stderr || error.message,
199→          });
200→          return;
201→        }
202→
203→        if (!output) {
204→          resolve({ success: true, data: null, error: null });
205→          return;
206→        }
207→
208→        resolve({ success: true, data: { text: output }, error: null });
209→      }
210→    );
211→
212→    child.on("error", (err) => reject(err));
213→  });
214→}
215→
216→/**
217→ * Execute an agent-browser command with stdin input (used for batch mode).
218→ * Uses spawn instead of execFile to pipe stdin data.
219→ */
220→export async function execAgentBrowserWithStdin(
221→  sessionId: string,
222→  args: string[],
223→  stdinData: string,
224→  timeoutMs = DEFAULT_TIMEOUT_MS
225→): Promise<AgentBrowserResult> {
226→  const finalArgs = await buildArgs(args);
227→  const env = buildEnv(sessionId);
228→
229→  return new Promise<AgentBrowserResult>((resolve, reject) => {
230→    const child = spawn(BINARY, finalArgs, {
231→      env,
232→      stdio: ["pipe", "pipe", "pipe"],
233→    });
234→
235→    const MAX_OUTPUT_BYTES = 10 * 1024 * 1024;
236→    let stdout = "";
237→    let stderr = "";
238→    let outputBytes = 0;
239→    let settled = false;
240→
241→    function abort(error: string): void {
242→      if (settled) return;
243→      settled = true;
244→      clearTimeout(timer);
245→      child.kill("SIGTERM");
246→      resolve({ success: false, data: null, error });
247→    }
248→
249→    const timer = setTimeout(() => abort("Batch timed out"), timeoutMs);
250→
251→    child.stdout.on("data", (chunk: Buffer) => {
252→      outputBytes += chunk.length;
253→      if (outputBytes > MAX_OUTPUT_BYTES) return abort("Batch output exceeded 10MB");
254→      stdout += chunk.toString();
255→    });
256→    child.stderr.on("data", (chunk: Buffer) => {
257→      outputBytes += chunk.length;
258→      if (outputBytes > MAX_OUTPUT_BYTES) return abort("Batch output exceeded 10MB");
259→      stderr += chunk.toString();
260→    });
261→
262→    child.on("close", (code) => {
263→      if (settled) return;
264→      settled = true;
265→      clearTimeout(timer);
266→
267→      const output = stdout.trim();
268→      const parsed = parseJsonFromOutput(output);
269→      if (parsed) {
270→        resolve(parsed);
271→        return;
272→      }
273→
274→      if (code !== 0) {
275→        resolve({
276→          success: false,
277→          data: output ? { text: output } : null,
278→          error: stderr || `Process exited with code ${code}`,
279→        });
280→        return;
281→      }
282→
283→      resolve({ success: true, data: output ? { text: output } : null, error: null });
284→    });
285→
286→    child.on("error", (err) => {
287→      if (!settled) {
288→        settled = true;
289→        clearTimeout(timer);
290→        reject(err);
291→      }
292→    });
293→
294→    // Write stdin data and close
295→    child.stdin.write(stdinData);
296→    child.stdin.end();
297→  });
298→}
