300→/**
301→ * Get an element's bounding box (best-effort, returns null on failure).
302→ * Used for screen recording cursor animation.
303→ */
304→export async function getElementBox(sessionId: string, ref: string): Promise<ElementBox | null> {
305→  try {
306→    const result = await execAgentBrowser(sessionId, ["get", "box", ref, "--json"], 5_000);
307→    if (!result.success || !result.data) return null;
308→    const d = result.data;
309→    if (typeof d.x === "number" && typeof d.y === "number") {
310→      return {
311→        x: d.x as number,
312→        y: d.y as number,
313→        width: (d.width as number) || 0,
314→        height: (d.height as number) || 0,
315→      };
316→    }
317→    return null;
318→  } catch {
319→    return null;
320→  }
321→}
322→
323→/**
324→ * Execute a batch of agent-browser commands in a single call.
325→ * Uses stdin-based batch mode for 10x fewer round-trips.
326→ *
327→ * Example: executeBatch(sessionId, [["click", "@e1"], ["fill", "@e3", "hello"]])
328→ */
329→export async function executeBatch(
330→  sessionId: string,
331→  commands: string[][],
332→  options?: { bail?: boolean; timeoutMs?: number }
333→): Promise<AgentBrowserResult> {
334→  const args = ["batch", "--json"];
335→  if (options?.bail) args.push("--bail");
336→  const stdinData = JSON.stringify(commands);
337→  return execAgentBrowserWithStdin(
338→    sessionId,
339→    args,
340→    stdinData,
341→    options?.timeoutMs ?? DEFAULT_TIMEOUT_MS
342→  );
343→}
344→
345→/**
346→ * Execute an agent-browser command and return snapshot + metadata.
347→ * Optionally fetches element bounding box for screen recording.
348→ *
349→ * Performance: snapshot, url, title, and box are fetched concurrently
350→ * via Promise.all (saves ~150ms vs sequential).
351→ */
352→export async function execWithSnapshot(
353→  sessionId: string,
354→  args: string[],
355→  timeoutMs?: number,
356→  interactedRef?: string
357→): Promise<{
358→  snapshot?: string;
359→  url?: string;
360→  title?: string;
361→  error?: string;
362→  elementBox?: ElementBox | null;
363→}> {
364→  try {
365→    const result = await execAgentBrowser(sessionId, args, timeoutMs);
366→    if (!result.success) {
367→      return { error: result.error || "Unknown error" };
368→    }
369→
370→    // Fetch metadata concurrently — all are independent read-only queries
371→    const [snapResult, urlResult, titleResult, box] = await Promise.all([
372→      execAgentBrowser(sessionId, ["snapshot", "--json"], timeoutMs),
373→      execAgentBrowser(sessionId, ["get", "url", "--json"]).catch(() => null),
374→      execAgentBrowser(sessionId, ["get", "title", "--json"]).catch(() => null),
375→      interactedRef ? getElementBox(sessionId, interactedRef) : Promise.resolve(null),
376→    ]);
377→
378→    if (!snapResult.success) {
379→      return { error: `Action succeeded but snapshot failed: ${snapResult.error || "unknown"}` };
380→    }
381→
382→    return {
383→      snapshot: (snapResult.data?.snapshot as string) || (snapResult.data?.text as string),
384→      url: (urlResult?.data?.url as string) || (urlResult?.data?.text as string),
385→      title: (titleResult?.data?.title as string) || (titleResult?.data?.text as string),
386→      elementBox: box,
387→    };
388→  } catch (err: unknown) {
389→    return { error: err instanceof Error ? err.message : String(err) };
390→  }
391→}
392→
393→/**
394→ * Get a snapshot with URL and title.
395→ * Supports optional filtering flags for smaller, more focused snapshots.
396→ */
397→export async function getSnapshot(
398→  sessionId: string,
399→  timeoutMs?: number,
400→  options?: {
401→    interactive?: boolean;
402→    compact?: boolean;
403→    depth?: number;
404→    selector?: string;
405→  }
406→): Promise<{ snapshot?: string; url?: string; title?: string; error?: string }> {
407→  try {
408→    const snapArgs = ["snapshot", "--json"];
409→    if (options?.interactive) snapArgs.push("-i");
410→    if (options?.compact) snapArgs.push("-c");
411→    if (options?.depth !== undefined) snapArgs.push("-d", String(options.depth));
412→    if (options?.selector) snapArgs.push("-s", options.selector);
413→
414→    const [snapResult, urlResult, titleResult] = await Promise.all([
415→      execAgentBrowser(sessionId, snapArgs, timeoutMs),
416→      execAgentBrowser(sessionId, ["get", "url", "--json"]).catch(() => null),
417→      execAgentBrowser(sessionId, ["get", "title", "--json"]).catch(() => null),
418→    ]);
419→
420→    if (!snapResult.success) {
421→      return { error: snapResult.error || "Snapshot failed" };
422→    }
423→
424→    return {
425→      snapshot: (snapResult.data?.snapshot as string) || (snapResult.data?.text as string),
426→      url: (urlResult?.data?.url as string) || (urlResult?.data?.text as string),
427→      title: (titleResult?.data?.title as string) || (titleResult?.data?.text as string),
428→    };
429→  } catch (err: unknown) {
430→    return { error: err instanceof Error ? err.message : String(err) };
431→  }
432→}
