32→    .readFileString(sessionPath)
33→    .pipe(
34→      Effect.catchTag("PlatformError", (error) =>
35→        new SessionLoadError({ path: sessionPath, cause: String(error) }).asEffect(),
36→      ),
37→    );
38→
39→  const lines = content.trim().split("\n");
40→  const events = yield* Effect.forEach(lines, (line, index) =>
41→    Effect.try({
42→      try: () => {
43→        const parsed: unknown = JSON.parse(line);
44→        if (!isRrwebEvent(parsed)) {
45→          throw new Error("Missing required 'type' and 'timestamp' fields");
46→        }
47→        return parsed;
48→      },
49→      catch: (cause) =>
50→        new SessionLoadError({
51→          path: sessionPath,
52→          cause: `Invalid rrweb event at line ${index + 1}: ${String(cause)}`,
53→        }),
54→    }),
55→  );
56→
57→  return events;
58→});
