  1→/**
  2→ * Video Renderer — full post-processing pipeline.
  3→ *
  4→ * FrameSource (decode) → CameraEngine (timeline) →
  5→ * per-frame canvas render → ffmpeg pipe (H.264 encode) → final MP4.
  6→ *
  7→ * Replaces the old zoompan ffmpeg filter approach.
  8→ */
  9→
 10→import { spawn, type ChildProcess } from "node:child_process";
 11→import type {
 12→  AgentEvent,
 13→  Size,
 14→  TimedTransform,
 15→  BackgroundConfig,
 16→  DeviceFrameConfig,
 17→  CursorConfig,
 18→} from "../types.js";
 19→import { CameraEngine } from "../camera/engine.js";
 20→import { FrameSource } from "./frame-source.js";
 21→import {
 22→  createPlaybackPlan,
 23→  outputToSourceTime,
 24→  type PlaybackPlan,
 25→} from "../recorder/render-plan.js";
 26→import {
 27→  createFrameRenderer,
 28→  renderFrame,
 29→  isCanvasAvailable,
 30→  type RenderConfig,
 31→} from "./frame-renderer.js";
 32→
 33→// ---------------------------------------------------------------------------
 34→// Types
 35→// ---------------------------------------------------------------------------
 36→
 37→export interface VideoRenderOptions {
 38→  rawVideoPath: string;
 39→  events: AgentEvent[];
 40→  sourceSize: Size;
 41→  outputSize: Size;
 42→  outputPath: string;
 43→  outputFps?: number;
 44→  speedRamp?: boolean;
 45→  background?: BackgroundConfig;
 46→  deviceFrame?: DeviceFrameConfig;
 47→  cursor?: CursorConfig;
 48→  onProgress?: (rendered: number, total: number) => void;
 49→}
 50→
 51→export interface VideoRenderResult {
 52→  outputPath: string;
 53→  durationSec: number;
 54→  frameCount: number;
 55→  canvasRendered: boolean;
 56→}
 57→
 58→// ---------------------------------------------------------------------------
 59→// Main render function
 60→// ---------------------------------------------------------------------------
 61→
 62→export async function renderVideo(
 63→  options: VideoRenderOptions
 64→): Promise<VideoRenderResult> {
 65→  const {
 66→    rawVideoPath,
 67→    events,
 68→    outputSize,
 69→    outputPath,
 70→    outputFps = 30,
 71→    speedRamp = false,
 72→    onProgress,
 73→  } = options;
 74→
 75→  // 1. Check canvas availability
 76→  const canvasOk = await isCanvasAvailable();
 77→  if (!canvasOk) {
 78→    return renderVideoFallback(options);
 79→  }
 80→
 81→  // 2. Decode all raw frames
 82→  const frameSource = new FrameSource(rawVideoPath);
 83→  let sourceInfo;
 84→  try {
 85→    sourceInfo = await frameSource.open();
 86→  } catch (err) {
 87→    throw new Error(`Failed to decode raw video: ${err instanceof Error ? err.message : err}`);
 88→  }
 89→
 90→  if (sourceInfo.frameCount === 0) {
 91→    frameSource.close();
 92→    throw new Error("Raw video has 0 frames");
 93→  }
 94→
 95→  const actualSourceSize: Size = {
 96→    width: sourceInfo.width,
 97→    height: sourceInfo.height,
 98→  };
 99→
100→  console.error(
101→    `[video-renderer] Source: ${sourceInfo.frameCount} frames, ` +
102→      `${sourceInfo.width}x${sourceInfo.height}, ${sourceInfo.fps.toFixed(1)}fps, ` +
103→      `${sourceInfo.durationSec.toFixed(1)}s`
104→  );
105→
106→  // 3. Generate camera timeline from events
107→  // Disable zoom for now — at 10fps input, zoom transitions look janky.
108→  // Camera still tracks cursor position for smooth panning.
109→  const engine = new CameraEngine({
110→    sourceSize: actualSourceSize,
111→    maxZoom: 1.0,
112→    minZoom: 1.0,
113→  });
114→  for (const event of events) {
115→    engine.pushEvent(event);
116→  }
117→
118→  const sourceDurationMs = sourceInfo.durationSec * 1000;
119→  const timeline = engine.processTimeline(outputFps, sourceInfo.durationSec);
120→
121→  // 4. Optionally build speed ramp plan
122→  let plan: PlaybackPlan | null = null;
123→  if (speedRamp && events.length > 0) {
124→    plan = createPlaybackPlan(events, sourceDurationMs);
125→    console.error(
126→      `[video-renderer] Speed ramp: ${(sourceDurationMs / 1000).toFixed(1)}s → ` +
127→        `${(plan.outputDurationMs / 1000).toFixed(1)}s (${plan.segments.length} segments)`
128→    );
129→  }
130→
131→  // 5. Compute output duration and frame count
132→  const outputDurationMs = plan ? plan.outputDurationMs : sourceDurationMs;
133→  const totalOutputFrames = Math.ceil((outputDurationMs / 1000) * outputFps);
134→
135→  // 6. Create frame renderer context
136→  const renderConfig: RenderConfig = {
137→    sourceSize: actualSourceSize,
138→    outputSize,
139→    background: options.background,
140→    deviceFrame: options.deviceFrame,
141→    cursor: options.cursor,
142→  };
143→
144→  const rendererCtx = await createFrameRenderer(renderConfig);
145→  if (!rendererCtx) {
146→    frameSource.close();
147→    return renderVideoFallback(options);
148→  }
149→
150→  // 7. Spawn ffmpeg encoder
151→  const ffmpeg = spawnEncoder(outputSize, outputFps, outputPath);
152→
153→  // 8. Render loop
154→  let renderedCount = 0;
155→  const msPerSourceFrame = 1000 / sourceInfo.fps;
156→  const timelineStartT = timeline.length > 0 ? timeline[0].t : 0;
157→
158→  try {
159→    for (let i = 0; i < totalOutputFrames; i++) {
160→      const outputTimeMs = (i / outputFps) * 1000;
161→
162→      // Map output time → source time
163→      const sourceTimeMs = plan
164→        ? outputToSourceTime(outputTimeMs, plan.segments)
165→        : outputTimeMs;
166→
167→      // Find source frame
168→      const sourceFrameIdx = Math.min(
169→        Math.max(0, Math.round(sourceTimeMs / msPerSourceFrame)),
170→        sourceInfo.frameCount - 1
171→      );
172→
173→      // Find camera transform
174→      const transform = findNearestTransform(
175→        timeline,
176→        timelineStartT + sourceTimeMs
177→      );
178→
179→      // Get source JPEG and render
180→      const sourceJpeg = frameSource.getFrame(sourceFrameIdx);
181→      const renderedJpeg = await renderFrame(
182→        sourceJpeg,
183→        transform,
184→        renderConfig,
185→        rendererCtx
186→      );
187→
188→      // Pipe to ffmpeg with backpressure handling
189→      const ok = ffmpeg.stdin!.write(renderedJpeg);
190→      if (!ok) {
191→        await new Promise<void>((r) => ffmpeg.stdin!.once("drain", r));
192→      }
193→
194→      renderedCount++;
195→      if (onProgress && renderedCount % 30 === 0) {
196→        onProgress(renderedCount, totalOutputFrames);
197→      }
198→    }
199→  } finally {
200→    frameSource.close();
201→  }
202→
203→  // 9. Wait for ffmpeg to finish
204→  await closeEncoder(ffmpeg);
205→
206→  console.error(
207→    `[video-renderer] Done: ${renderedCount} frames, ${(outputDurationMs / 1000).toFixed(1)}s`
208→  );
209→
210→  return {
211→    outputPath,
212→    durationSec: outputDurationMs / 1000,
213→    frameCount: renderedCount,
214→    canvasRendered: true,
215→  };
216→}
217→
218→// ---------------------------------------------------------------------------
219→// Timeline lookup
220→// ---------------------------------------------------------------------------
221→
222→function findNearestTransform(
223→  timeline: TimedTransform[],
224→  timeMs: number
225→): TimedTransform {
226→  if (timeline.length === 0) {
227→    return {
228→      t: timeMs,
229→      camera: { x: 640, y: 360, zoom: 1 },
230→      cursor: {
231→        x: 640, y: 360,
232→        clicking: false, clickAge: 0,
233→        visible: false, vx: 0, vy: 0,
234→      },
235→    };
236→  }
237→
238→  if (timeMs <= timeline[0].t) return timeline[0];
239→  if (timeMs >= timeline[timeline.length - 1].t) return timeline[timeline.length - 1];
240→
241→  // Binary search
242→  let lo = 0;
243→  let hi = timeline.length - 1;
244→  while (lo < hi - 1) {
245→    const mid = (lo + hi) >> 1;
246→    if (timeline[mid].t <= timeMs) lo = mid;
247→    else hi = mid;
248→  }
249→
250→  return (timeMs - timeline[lo].t <= timeline[hi].t - timeMs)
251→    ? timeline[lo]
252→    : timeline[hi];
253→}
254→
255→// ---------------------------------------------------------------------------
256→// ffmpeg encoder
257→// ---------------------------------------------------------------------------
258→
259→function spawnEncoder(
260→  outputSize: Size,
261→  fps: number,
262→  outputPath: string
263→): ChildProcess {
264→  const proc = spawn("ffmpeg", [
265→    "-y",
266→    "-f", "image2pipe",
267→    "-framerate", String(fps),
268→    "-c:v", "mjpeg",
269→    "-i", "pipe:0",
270→    "-c:v", "libx264",
271→    "-preset", "slow",
272→    "-crf", "22",
273→    "-pix_fmt", "yuv420p",
274→    "-s", `${outputSize.width}x${outputSize.height}`,
275→    outputPath,
276→  ], { stdio: ["pipe", "ignore", "pipe"] });
277→
278→  proc.stderr?.on("data", () => {});
279→  proc.on("error", (err: Error) => {
280→    console.error(`[video-renderer] ffmpeg error: ${err.message}`);
281→  });
282→
283→  return proc;
284→}
285→
286→async function closeEncoder(proc: ChildProcess): Promise<void> {
287→  return new Promise<void>((resolve, reject) => {
288→    const killTimer = setTimeout(() => proc.kill("SIGKILL"), 30_000);
289→
290→    proc.on("close", (code) => {
291→      clearTimeout(killTimer);
292→      if (code === 0) resolve();
293→      else reject(new Error(`ffmpeg encoder exited with code ${code}`));
294→    });
295→
296→    if (proc.stdin?.writable) proc.stdin.end();
297→    else proc.kill("SIGINT");
298→  });
299→}
300→
301→// ---------------------------------------------------------------------------
302→// Fallback: ffmpeg-only scale (no canvas)
303→// ---------------------------------------------------------------------------
304→
305→async function renderVideoFallback(
306→  options: VideoRenderOptions
307→): Promise<VideoRenderResult> {
308→  const { rawVideoPath, outputSize, outputPath, outputFps = 30 } = options;
309→
310→  console.error("[video-renderer] Canvas not available, using ffmpeg scale fallback");
311→
312→  return new Promise<VideoRenderResult>((resolve, reject) => {
313→    const proc = spawn("ffmpeg", [
314→      "-y",
315→      "-i", rawVideoPath,
316→      "-vf", `scale=${outputSize.width}:${outputSize.height}:flags=lanczos`,
317→      "-c:v", "libx264",
318→      "-preset", "slow",
319→      "-crf", "22",
320→      "-pix_fmt", "yuv420p",
321→      "-r", String(outputFps),
322→      outputPath,
323→    ], { stdio: ["ignore", "ignore", "pipe"] });
324→
325→    proc.stderr?.on("data", () => {});
326→    proc.on("error", (err) => reject(new Error(`ffmpeg fallback failed: ${err.message}`)));
327→    proc.on("close", (code) => {
328→      if (code === 0) {
329→        resolve({ outputPath, durationSec: 0, frameCount: 0, canvasRendered: false });
330→      } else {
331→        reject(new Error(`ffmpeg fallback exited with code ${code}`));
332→      }
333→    });
334→  });
335→}
