  1→import { execFileSync } from "node:child_process";
  2→
  3→// ---------------------------------------------------------------------------
  4→// Types
  5→// ---------------------------------------------------------------------------
  6→
  7→/** Metadata returned after probing and decoding a video. */
  8→export interface FrameSourceInfo {
  9→  width: number;
 10→  height: number;
 11→  frameCount: number;
 12→  fps: number;
 13→  durationSec: number;
 14→}
 15→
 16→// ---------------------------------------------------------------------------
 17→// JPEG splitter
 18→// ---------------------------------------------------------------------------
 19→
 20→const SOI = 0xffd8;
 21→const EOI = 0xffd9;
 22→
 23→/**
 24→ * Split a concatenated stream of JPEG images (image2pipe output) into
 25→ * individual Buffer segments. Each JPEG starts with FFD8 and ends with FFD9.
 26→ */
 27→export function splitJpegFrames(buffer: Buffer): Buffer[] {
 28→  const frames: Buffer[] = [];
 29→  let start = -1;
 30→
 31→  for (let i = 0; i < buffer.length - 1; i++) {
 32→    const marker = (buffer[i] << 8) | buffer[i + 1];
 33→
 34→    if (marker === SOI && start === -1) {
 35→      start = i;
 36→    } else if (marker === EOI && start !== -1) {
 37→      frames.push(buffer.subarray(start, i + 2));
 38→      start = -1;
 39→      i += 1;
 40→    }
 41→  }
 42→
 43→  return frames;
 44→}
 45→
 46→// ---------------------------------------------------------------------------
 47→// FrameSource
 48→// ---------------------------------------------------------------------------
 49→
 50→/**
 51→ * Reads a raw MP4 video and provides random access to individual JPEG frames.
 52→ *
 53→ * Decodes all frames into memory on open() — designed for recordings under
 54→ * 5 minutes (~600 frames at 10fps = ~30MB of JPEG data).
 55→ *
 56→ * Usage:
 57→ * ```ts
 58→ * const src = new FrameSource("/path/to/raw.mp4");
 59→ * const info = await src.open();
 60→ * const jpeg = src.getFrame(0);
 61→ * src.close();
 62→ * ```
 63→ */
 64→export class FrameSource {
 65→  private readonly videoPath: string;
 66→  private frames: Buffer[] | null = null;
 67→  private info: FrameSourceInfo | null = null;
 68→
 69→  constructor(videoPath: string) {
 70→    this.videoPath = videoPath;
 71→  }
 72→
 73→  /**
 74→   * Probe the video for metadata, then decode every frame as JPEG into memory.
 75→   */
 76→  async open(): Promise<FrameSourceInfo> {
 77→    if (this.frames !== null) {
 78→      throw new Error("FrameSource is already opened. Call close() first.");
 79→    }
 80→
 81→    // Step 1: probe with ffprobe
 82→    const probeJson = execFileSync("ffprobe", [
 83→      "-v", "quiet",
 84→      "-print_format", "json",
 85→      "-show_streams", "-show_format",
 86→      "-select_streams", "v:0",
 87→      this.videoPath,
 88→    ], { encoding: "utf-8", timeout: 10_000 });
 89→
 90→    const probe = JSON.parse(probeJson);
 91→    const stream = probe.streams?.[0];
 92→    if (!stream) {
 93→      throw new Error(`No video stream found in ${this.videoPath}`);
 94→    }
 95→
 96→    const width = Number(stream.width);
 97→    const height = Number(stream.height);
 98→    const fps = parseFrameRate(stream.r_frame_rate ?? stream.avg_frame_rate ?? "30/1");
 99→    const durationSec = parseDuration(stream, probe);
100→
101→    // Step 2: decode all frames to JPEG via image2pipe
102→    const rawJpegs = execFileSync("ffmpeg", [
103→      "-i", this.videoPath,
104→      "-f", "image2pipe",
105→      "-c:v", "mjpeg",
106→      "-q:v", "2",
107→      "pipe:1",
108→    ], { timeout: 60_000, maxBuffer: 512 * 1024 * 1024 });
109→
110→    // Step 3: split concatenated JPEG stream
111→    this.frames = splitJpegFrames(Buffer.from(rawJpegs));
112→
113→    this.info = {
114→      width,
115→      height,
116→      frameCount: this.frames.length,
117→      fps,
118→      durationSec,
119→    };
120→
121→    return this.info;
122→  }
123→
124→  /**
125→   * Get a decoded JPEG frame by index.
126→   */
127→  getFrame(index: number): Buffer {
128→    if (this.frames === null) {
129→      throw new Error("FrameSource is not opened. Call open() first.");
130→    }
131→    if (index < 0 || index >= this.frames.length) {
132→      throw new RangeError(
133→        `Frame index ${index} out of range [0, ${this.frames.length - 1}]`
134→      );
135→    }
136→    return this.frames[index];
137→  }
138→
139→  /** Number of decoded frames, or 0 if not yet opened. */
140→  get frameCount(): number {
141→    return this.frames?.length ?? 0;
142→  }
143→
144→  /** Return probe info, or null if not yet opened. */
145→  getInfo(): FrameSourceInfo | null {
146→    return this.info;
147→  }
148→
149→  /** Release all frame buffers. */
150→  close(): void {
151→    this.frames = null;
152→    this.info = null;
153→  }
154→}
155→
156→// ---------------------------------------------------------------------------
157→// Helpers
158→// ---------------------------------------------------------------------------
159→
160→function parseFrameRate(rate: string): number {
161→  const parts = rate.split("/");
162→  if (parts.length === 2) {
163→    const num = Number(parts[0]);
164→    const den = Number(parts[1]);
165→    if (den !== 0) return num / den;
166→  }
167→  const n = Number(rate);
168→  return isNaN(n) ? 30 : n;
169→}
170→
171→function parseDuration(
172→  stream: Record<string, unknown>,
173→  probe: Record<string, unknown>,
174→): number {
175→  if (stream.duration && Number(stream.duration) > 0) {
176→    return Number(stream.duration);
177→  }
178→  if (stream.nb_frames && stream.r_frame_rate) {
179→    const fps = parseFrameRate(stream.r_frame_rate as string);
180→    const frames = Number(stream.nb_frames);
181→    if (frames > 0 && fps > 0) return frames / fps;
182→  }
183→  const format = probe.format as Record<string, unknown> | undefined;
184→  if (format?.duration && Number(format.duration) > 0) {
185→    return Number(format.duration);
186→  }
187→  return 0;
188→}
