 5→// HACK: page.evaluate erases types across the serialization boundary; casts are confined here
 6→export const evaluateRuntime = <K extends keyof ExpectRuntime>(
 7→  page: Page,
 8→  method: K,
 9→  ...args: Parameters<ExpectRuntime[K]>
10→) =>
11→  Effect.promise(
12→    () =>
13→      page.evaluate(
14→        ({ method, args }: { method: string; args: unknown[] }) => {
15→          const runtime = Reflect.get(globalThis, "__EXPECT_RUNTIME__");
16→          if (!runtime || typeof runtime !== "object") {
17→            throw new Error("Browser runtime is not initialized");
18→          }
19→
20→          const fn = Reflect.get(runtime, method);
21→          if (typeof fn !== "function") {
22→            throw new Error(`Browser runtime method not found: ${method}`);
23→          }
24→
25→          return fn(...args);
26→        },
27→        { method, args: args as unknown[] },
28→      ) as Promise<ReturnType<ExpectRuntime[K]>>,
29→  );
