 1→import { context } from "esbuild";
 2→import * as fs from "node:fs";
 3→
 4→const watchMode = process.argv.includes("--watch");
 5→
 6→const RUNTIME_ENTRY = "src/runtime/index.ts";
 7→
 8→const extractExportedFunctionNames = (source) => {
 9→  const regex = /export\s+const\s+(\w+)\s*=/g;
10→  const names = [];
11→  let match;
12→  while ((match = regex.exec(source)) !== null) {
13→    names.push(match[1]);
14→  }
15→  return names;
16→};
17→
18→const generateRuntimeTypes = (exportNames) => {
19→  const fields = exportNames.map((name) => `  ${name}: typeof Runtime.${name};`).join("\n");
20→  return [
21→    `import type * as Runtime from "../runtime/index";`,
22→    ``,
23→    `export interface ExpectRuntime {`,
24→    fields,
25→    `}`,
26→    ``,
27→  ].join("\n");
28→};
29→
30→const emitPlugin = {
31→  name: "emit-runtime-script",
32→  setup(build) {
33→    build.onEnd((result) => {
34→      if (result.errors.length > 0) return;
35→      const runtimeCode =
36→        `${result.outputFiles[0].text}\n` + "globalThis.__EXPECT_RUNTIME__ = __EXPECT_RUNTIME__;\n";
37→      fs.mkdirSync("src/generated", { recursive: true });
38→      fs.writeFileSync(
39→        "src/generated/runtime-script.ts",
40→        `export const RUNTIME_SCRIPT = ${JSON.stringify(runtimeCode)};\n`,
41→      );
42→
43→      const source = fs.readFileSync(RUNTIME_ENTRY, "utf-8");
44→      const exportNames = extractExportedFunctionNames(source);
45→      fs.writeFileSync("src/generated/runtime-types.ts", generateRuntimeTypes(exportNames));
46→    });
47→  },
48→};
49→
50→const ctx = await context({
51→  entryPoints: ["src/runtime/index.ts"],
52→  bundle: true,
53→  format: "iife",
54→  globalName: "__EXPECT_RUNTIME__",
55→  write: false,
56→  minify: true,
57→  target: "es2020",
58→  plugins: [emitPlugin],
59→});
60→
61→if (watchMode) {
62→  await ctx.watch();
63→} else {
64→  await ctx.rebuild();
65→  await ctx.dispose();
66→}
