 79→const performanceState = {
 80→  fcp: null as number | null,
 81→  lcp: null as number | null,
 82→  cls: 0,
 83→  interactionDurations: new Map<number, number>(),
 84→  loafEntries: [] as LoafEntry[],
 85→};
