 87→const THRESHOLDS: Record<string, [number, number]> = {
 88→  FCP: [FCP_GOOD_MS, FCP_POOR_MS],
 89→  LCP: [LCP_GOOD_MS, LCP_POOR_MS],
 90→  CLS: [CLS_GOOD, CLS_POOR],
 91→  INP: [INP_GOOD_MS, INP_POOR_MS],
 92→};
 93→
 94→const ratePerformanceMetric = (name: string, value: number): string => {
 95→  const threshold = THRESHOLDS[name];
 96→  if (!threshold) return "unknown";
 97→  if (value < threshold[0]) return "good";
 98→  if (value < threshold[1]) return "needs-improvement";
 99→  return "poor";
100→};
