102→try {
103→  new PerformanceObserver((list) => {
104→    for (const entry of list.getEntries()) {
105→      if (entry.name === "first-contentful-paint") {
106→        performanceState.fcp = entry.startTime;
107→      }
108→    }
109→  }).observe({ type: "paint", buffered: true });
110→} catch {}
111→
112→try {
113→  new PerformanceObserver((list) => {
114→    for (const entry of list.getEntries()) {
115→      performanceState.lcp = entry.startTime;
116→    }
117→  }).observe({ type: "largest-contentful-paint", buffered: true });
118→} catch {}
119→
120→try {
121→  new PerformanceObserver((list) => {
122→    for (const entry of list.getEntries()) {
123→      const { interactionId } = entry as EventTimingEntry;
124→      if (interactionId && interactionId > 0) {
125→        const current = performanceState.interactionDurations.get(interactionId) ?? 0;
126→        performanceState.interactionDurations.set(interactionId, Math.max(current, entry.duration));
127→      }
128→    }
129→  }).observe({
130→    type: "event",
131→    buffered: true,
132→    durationThreshold: INP_DURATION_THRESHOLD_MS,
133→  } as PerformanceObserverInit);
134→} catch {}
135→
136→try {
137→  const sessionEntries: LayoutShiftEntry[] = [];
138→  new PerformanceObserver((list) => {
139→    for (const entry of list.getEntries()) {
140→      const shiftEntry = entry as LayoutShiftEntry;
141→      if (shiftEntry.hadRecentInput) continue;
142→      sessionEntries.push(shiftEntry);
143→    }
144→    let maxSessionValue = 0;
145→    let currentSessionValue = 0;
146→    let currentSessionStart = 0;
147→    let previousEntryEnd = 0;
148→    for (const entry of sessionEntries) {
149→      if (
150→        entry.startTime - previousEntryEnd > CLS_SESSION_GAP_MS ||
151→        entry.startTime - currentSessionStart > CLS_SESSION_CAP_MS
152→      ) {
153→        currentSessionValue = 0;
154→        currentSessionStart = entry.startTime;
155→      }
156→      currentSessionValue += entry.value;
157→      previousEntryEnd = entry.startTime + entry.duration;
158→      if (currentSessionValue > maxSessionValue) {
159→        maxSessionValue = currentSessionValue;
160→      }
161→    }
162→    performanceState.cls = maxSessionValue;
163→  }).observe({ type: "layout-shift", buffered: true });
164→} catch {}
