  2→import type { Page } from "playwright";
  3→import type { eventWithTime } from "@rrweb/types";
  4→import { Effect, Fiber, Predicate, PubSub, Schedule, Stream } from "effect";
  5→import { EVENT_COLLECT_INTERVAL_MS } from "../constants";
  6→import { buildReplayViewerHtml } from "../replay-viewer";
  7→import { evaluateRuntime } from "../utils/evaluate-runtime";
  8→import type { ViewerRunState } from "./viewer-events";
  9→
 10→const isViewerRunState = (value: unknown): value is ViewerRunState =>
 11→  Predicate.isObject(value) &&
 12→  "status" in value &&
 13→  "steps" in value &&
 14→  Array.isArray((value as Record<string, unknown>).steps);
 15→
 16→export interface LiveViewHandle {
 17→  readonly url: string;
 18→  readonly pushRunState: (state: ViewerRunState) => void;
 19→  readonly getLatestRunState: () => ViewerRunState | undefined;
 20→  readonly close: Effect.Effect<void>;
 21→}
 22→
 23→export interface StartLiveViewServerOptions {
 24→  readonly liveViewUrl: string;
 25→  readonly getPage: () => Page | undefined;
 26→  readonly onEventsCollected: (events: eventWithTime[]) => void;
 27→}
 28→
 29→type SseClient = ServerResponse<IncomingMessage>;
 30→
 31→const CORS_HEADERS = {
 32→  "Access-Control-Allow-Origin": "*",
 33→  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
 34→  "Access-Control-Allow-Headers": "Content-Type",
 35→} as const;
 36→
 37→const NO_CACHE_HEADERS = { "Cache-Control": "no-store" } as const;
 38→
 39→const listenServer = (server: Server, host: string, port: number) =>
 40→  Effect.callback<void, Error>((resume) => {
 41→    const onError = (error: Error) => resume(Effect.fail(error));
 42→    server.once("error", onError);
 43→    server.listen({ host, port }, () => {
 44→      server.off("error", onError);
 45→      resume(Effect.void);
 46→    });
 47→  });
 48→
 49→const closeServer = (server: Server) =>
 50→  Effect.callback<void>((resume) => {
 51→    server.close(() => resume(Effect.void));
 52→  });
 53→
 54→export const startLiveViewServer = Effect.fn("LiveViewServer.start")(function* (
 55→  options: StartLiveViewServerOptions,
 56→) {
 57→  const parsedUrl = new URL(options.liveViewUrl);
 58→  const sseClients = new Set<SseClient>();
 59→  const accumulatedReplayEvents: eventWithTime[] = [];
 60→  let latestRunState: ViewerRunState | undefined;
 61→
 62→  const stepsPubSub = yield* PubSub.unbounded<ViewerRunState>();
 63→
 64→  const viewerHtml = buildReplayViewerHtml({
 65→    title: "Expect Live View",
 66→    eventsSource: "sse",
 67→  });
 68→
 69→  const broadcastSse = (eventType: string, data: string): void => {
 70→    const message = `event: ${eventType}\ndata: ${data}\n\n`;
 71→    for (const client of sseClients) {
 72→      if (client.destroyed) {
 73→        sseClients.delete(client);
 74→        continue;
 75→      }
 76→      try {
 77→        client.write(message);
 78→      } catch {
 79→        sseClients.delete(client);
 80→        client.end();
 81→      }
 82→    }
 83→  };
 84→
 85→  const broadcastReplayEvents = (events: eventWithTime[]): void => {
 86→    if (events.length === 0) return;
 87→    accumulatedReplayEvents.push(...events);
 88→    options.onEventsCollected(events);
 89→    broadcastSse("replay", JSON.stringify(events));
 90→  };
 91→
 92→  const broadcastRunState = (state: ViewerRunState): void => {
 93→    latestRunState = state;
 94→    broadcastSse("steps", JSON.stringify(state));
 95→  };
 96→
 97→  const handleSseRequest = (request: IncomingMessage, response: SseClient): void => {
 98→    response.writeHead(200, {
 99→      "Content-Type": "text/event-stream",
100→      Connection: "keep-alive",
101→      ...CORS_HEADERS,
102→      ...NO_CACHE_HEADERS,
103→    });
104→    response.flushHeaders();
105→    sseClients.add(response);
106→    request.on("close", () => sseClients.delete(response));
107→  };
108→
109→  const handleStepsPost = (request: IncomingMessage, response: SseClient): void => {
110→    const chunks: Buffer[] = [];
111→    request.on("data", (chunk: Buffer) => chunks.push(chunk));
112→    request.on("end", () => {
113→      try {
114→        const body = Buffer.concat(chunks).toString("utf-8");
115→        const parsed: unknown = JSON.parse(body);
116→        if (!isViewerRunState(parsed)) {
117→          response.writeHead(400, {
118→            "Content-Type": "text/plain",
119→            ...CORS_HEADERS,
120→            ...NO_CACHE_HEADERS,
121→          });
122→          response.end("Invalid step state: missing status or steps");
123→          return;
124→        }
125→        broadcastRunState(parsed);
126→        response.writeHead(204, { ...CORS_HEADERS, ...NO_CACHE_HEADERS });
127→        response.end();
128→      } catch {
129→        response.writeHead(400, {
130→          "Content-Type": "text/plain",
131→          ...CORS_HEADERS,
132→          ...NO_CACHE_HEADERS,
133→        });
134→        response.end("Invalid JSON");
135→      }
136→    });
137→  };
138→
139→  const routeRequest = (request: IncomingMessage, response: SseClient): void => {
140→    if (request.method === "OPTIONS") {
141→      response.writeHead(204, CORS_HEADERS);
142→      response.end();
143→      return;
144→    }
145→
146→    const pathname = new URL(request.url ?? "/", parsedUrl).pathname;
147→
148→    if (pathname === "/") {
149→      response.writeHead(200, {
150→        "Content-Type": "text/html; charset=utf-8",
151→        ...CORS_HEADERS,
152→        ...NO_CACHE_HEADERS,
153→      });
154→      response.end(viewerHtml);
155→      return;
156→    }
157→
158→    if (pathname === "/events") {
159→      handleSseRequest(request, response);
160→      return;
161→    }
162→
163→    if (pathname === "/latest.json") {
164→      const body = JSON.stringify(accumulatedReplayEvents);
165→      response.writeHead(200, {
166→        "Content-Type": "application/json",
167→        "Content-Length": Buffer.byteLength(body),
168→        ...CORS_HEADERS,
169→        ...NO_CACHE_HEADERS,
170→      });
171→      response.end(body);
172→      return;
173→    }
174→
175→    if (pathname === "/steps") {
176→      if (request.method === "POST") {
177→        handleStepsPost(request, response);
178→        return;
179→      }
180→      const body = JSON.stringify(latestRunState ?? { title: "", status: "running", steps: [] });
181→      response.writeHead(200, {
182→        "Content-Type": "application/json",
