 90→const TMP_ARTIFACT_OUTPUT_DIRECTORY = "/tmp/expect-replays";
 91→const PLAYWRIGHT_VIDEO_SUBDIRECTORY = "playwright";
 92→
 93→const setupPageTracking = (page: Page, sessionData: BrowserSessionData) => {
 94→  if (sessionData.trackedPages.has(page)) return;
 95→  sessionData.trackedPages.add(page);
 96→
 97→  page.on("console", (message) => {
 98→    sessionData.consoleMessages.push({
 99→      type: message.type(),
100→      text: message.text(),
101→      timestamp: Date.now(),
102→    });
103→  });
104→
105→  page.on("request", (request) => {
106→    sessionData.networkRequests.push({
107→      url: request.url(),
108→      method: request.method(),
109→      status: undefined,
110→      resourceType: request.resourceType(),
111→      timestamp: Date.now(),
112→    });
113→  });
114→
115→  page.on("response", (response) => {
116→    const entry = sessionData.networkRequests.find(
117→      (networkEntry) => networkEntry.url === response.url() && networkEntry.status === undefined,
118→    );
119→    if (entry) entry.status = response.status();
120→  });
121→};
122→
123→export class McpSession extends ServiceMap.Service<McpSession>()("@browser/McpSession", {
124→  make: Effect.gen(function* () {
125→    const browserService = yield* Browser;
126→    const fileSystem = yield* FileSystem;
127→    const replayOutputPath = yield* Config.option(Config.string(EXPECT_REPLAY_OUTPUT_ENV_NAME));
128→    const liveViewUrl = yield* Config.option(Config.string(EXPECT_LIVE_VIEW_URL_ENV_NAME));
129→    const cookieBrowsersConfig = yield* Config.option(
130→      Config.string(EXPECT_COOKIE_BROWSERS_ENV_NAME),
131→    );
132→    const cdpUrlConfig = yield* Config.option(Config.string(EXPECT_CDP_URL_ENV_NAME));
133→    const defaultCdpUrl = Option.getOrUndefined(cdpUrlConfig);
134→    const cookieBrowserKeys = Option.match(cookieBrowsersConfig, {
135→      onNone: () => [] as string[],
136→      onSome: (value) => value.split(",").filter(Boolean),
137→    });
138→    const cookiesDisabled = cookieBrowserKeys.length === 0;
139→
140→    const sessionRef = yield* Ref.make<BrowserSessionData | undefined>(undefined);
141→    const iosSessionRef = yield* Ref.make<IosSessionData | undefined>(undefined);
142→    const iosScopeRef = yield* Ref.make<Scope.Closeable | undefined>(undefined);
143→    const liveViewRef = yield* Ref.make<LiveViewHandle | undefined>(undefined);
144→    const pollingFiberRef = yield* Ref.make<Fiber.Fiber<unknown> | undefined>(undefined);
145→    const latestRunStateRef = yield* Ref.make<ViewerRunState | undefined>(undefined);
146→    const preExtractedCookiesRef = yield* Ref.make<Cookie[] | undefined>(undefined);
147→
148→    if (!cookiesDisabled) {
149→      yield* browserService.preExtractCookies(cookieBrowserKeys).pipe(
150→        Effect.tap((cookies) => Ref.set(preExtractedCookiesRef, cookies)),
151→        Effect.tap((cookies) => Effect.logInfo("Cookies pre-extracted", { count: cookies.length })),
152→        Effect.catchCause((cause) => Effect.logWarning("Cookie pre-extraction failed", { cause })),
153→        Effect.forkDetach,
154→      );
155→    }
156→
157→    const requireSession = Effect.fn("McpSession.requireSession")(function* () {
158→      const session = yield* Ref.get(sessionRef);
159→      if (!session) return yield* new McpSessionNotOpenError();
160→      return session;
161→    });
162→
163→    const requirePage = Effect.fn("McpSession.requirePage")(function* () {
164→      return (yield* requireSession()).page;
165→    });
166→
167→    const requireIosSession = Effect.fn("McpSession.requireIosSession")(function* () {
168→      const iosSession = yield* Ref.get(iosSessionRef);
169→      if (!iosSession) return yield* new McpSessionNotOpenError();
170→      return iosSession;
171→    });
172→
173→    const navigate = Effect.fn("McpSession.navigate")(function* (
174→      url: string,
175→      options: { waitUntil?: "load" | "domcontentloaded" | "networkidle" | "commit" } = {},
176→    ) {
177→      const sessionData = yield* requireSession();
178→      yield* Effect.tryPromise({
179→        try: () => sessionData.page.goto(url, { waitUntil: options.waitUntil ?? "load" }),
180→        catch: (cause) =>
181→          new NavigationError({
182→            url,
183→            cause: cause instanceof Error ? cause.message : String(cause),
184→          }),
185→      });
186→    });
187→
188→    const pushStepEvent = Effect.fn("McpSession.pushStepEvent")(function* (state: ViewerRunState) {
189→      yield* Ref.set(latestRunStateRef, state);
190→      const liveView = yield* Ref.get(liveViewRef);
191→      if (liveView) {
192→        liveView.pushRunState(state);
193→      }
194→    });
195→
196→    const open = Effect.fn("McpSession.open")(function* (url: string, options: OpenOptions = {}) {
197→      yield* Effect.annotateCurrentSpan({ url });
198→
199→      const preExtracted = options.cookies ? yield* Ref.get(preExtractedCookiesRef) : undefined;
200→      const cookiesOption =
201→        preExtracted && preExtracted.length > 0 ? preExtracted : options.cookies;
202→      const videoOutputDir = path.join(
203→        TMP_ARTIFACT_OUTPUT_DIRECTORY,
204→        PLAYWRIGHT_VIDEO_SUBDIRECTORY,
205→      );
206→
207→      yield* fileSystem
208→        .makeDirectory(videoOutputDir, { recursive: true })
209→        .pipe(
210→          Effect.catchCause((cause) =>
211→            Effect.logDebug("Failed to create Playwright video directory", { cause }),
212→          ),
213→        );
214→
215→      const pageResult = yield* browserService.createPage(url, {
216→        headed: options.headed,
217→        cookies: cookiesOption,
218→        waitUntil: options.waitUntil,
219→        videoOutputDir,
220→        cdpUrl: options.cdpUrl ?? defaultCdpUrl,
221→      });
222→
223→      const sessionData: BrowserSessionData = {
224→        browser: pageResult.browser,
225→        context: pageResult.context,
226→        page: pageResult.page,
227→        consoleMessages: [],
228→        networkRequests: [],
229→        replayOutputPath: Option.getOrUndefined(replayOutputPath),
230→        accumulatedReplayEvents: [],
231→        trackedPages: new Set(),
232→        lastSnapshot: undefined,
233→      };
234→      setupPageTracking(pageResult.page, sessionData);
235→      yield* Ref.set(sessionRef, sessionData);
236→
237→      yield* evaluateRuntime(pageResult.page, "startRecording").pipe(
238→        Effect.catchCause((cause) => Effect.logDebug("rrweb recording failed to start", { cause })),
239→      );
240→
241→      const existingLiveView = yield* Ref.get(liveViewRef);
242→      if (Option.isSome(liveViewUrl) && !existingLiveView) {
243→        const handle = yield* startLiveViewServer({
244→          liveViewUrl: liveViewUrl.value,
245→          getPage: () => Ref.getUnsafe(sessionRef)?.page,
246→          onEventsCollected: (events) => {
247→            Ref.getUnsafe(sessionRef)?.accumulatedReplayEvents.push(...events);
248→          },
249→        }).pipe(
250→          Effect.catchCause((cause) =>
251→            Effect.logDebug("Live view server failed to start", { cause }).pipe(
252→              Effect.as(undefined),
253→            ),
254→          ),
255→        );
256→        if (handle) {
257→          yield* Ref.set(liveViewRef, handle);
258→        }
259→      }
260→
261→      const hasLiveView = Boolean(yield* Ref.get(liveViewRef));
262→      if (!hasLiveView) {
263→        const pollPage = Effect.sync(() => Ref.getUnsafe(sessionRef)?.page).pipe(
264→          Effect.flatMap((page) => {
265→            if (!page || page.isClosed()) return Effect.void;
266→            return evaluateRuntime(page, "startRecording").pipe(
267→              Effect.catchCause(() => Effect.void),
268→              Effect.flatMap(() => evaluateRuntime(page, "getEvents")),
269→              Effect.tap((events) =>
270→                Effect.sync(() => {
271→                  if (Array.isArray(events) && events.length > 0) {
272→                    Ref.getUnsafe(sessionRef)?.accumulatedReplayEvents.push(...events);
273→                  }
274→                }),
275→              ),
276→              Effect.catchCause((cause) =>
277→                Effect.logDebug("Replay event collection failed", { cause }),
278→              ),
279→            );
280→          }),
281→        );
282→
283→        const fiber = yield* pollPage.pipe(
284→          Effect.repeat(Schedule.spaced(EVENT_COLLECT_INTERVAL_MS)),
285→          Effect.forkDetach,
286→        );
287→        yield* Ref.set(pollingFiberRef, fiber);
288→      }
289→
290→      const injectedCookieCount = yield* Effect.tryPromise(() => pageResult.context.cookies()).pipe(
291→        Effect.map((cookies) => cookies.length),
292→        Effect.catchCause((cause) =>
293→          Effect.logDebug("Failed to count cookies", { cause }).pipe(Effect.as(0)),
294→        ),
295→      );
296→
297→      return { injectedCookieCount } satisfies OpenResult;
298→    });
299→
300→    const openIos = Effect.fn("McpSession.openIos")(function* (url: string, deviceName?: string) {
301→      yield* Effect.annotateCurrentSpan({ url, deviceName });
302→
303→      const device = yield* selectDevice(deviceName);
304→
305→      if (!device.isReal && device.state !== "Booted") {
306→        yield* bootSimulator(device.udid);
307→      }
308→
309→      const platformVersion = extractPlatformVersion(device.runtime);
310→
311→      const scope = yield* Scope.make();
312→      const iosSession = yield* createIosSession(device.udid, device.name, platformVersion).pipe(
313→        Effect.provideService(Scope.Scope, scope),
314→      );
315→
316→      yield* Ref.set(iosSessionRef, iosSession);
317→      yield* Ref.set(iosScopeRef, scope);
318→
319→      yield* iosSession.client.navigate(url);
320→
321→      yield* Effect.logInfo("iOS session opened", {
322→        device: device.name,
323→        udid: device.udid,
324→        url,
325→      });
326→
327→      return { device: device.name, udid: device.udid };
328→    });
329→
330→    const snapshot = Effect.fn("McpSession.snapshot")(function* (
331→      page: Page,
332→      options?: SnapshotOptions,
333→    ) {
334→      return yield* browserService.snapshot(page, options);
335→    });
336→
337→    const annotatedScreenshot = Effect.fn("McpSession.annotatedScreenshot")(function* (
338→      page: Page,
339→      options?: AnnotatedScreenshotOptions,
340→    ) {
341→      return yield* browserService.annotatedScreenshot(page, options);
342→    });
343→
344→    const updateLastSnapshot = Effect.fn("McpSession.updateLastSnapshot")(function* (
345→      snapshotResult: SnapshotResult,
346→    ) {
347→      const sessionData = yield* requireSession();
348→      sessionData.lastSnapshot = snapshotResult;
349→    });
350→
351→    const close = Effect.fn("McpSession.close")(function* () {
352→      const iosScope = yield* Ref.get(iosScopeRef);
353→      if (iosScope) {
354→        yield* Scope.close(iosScope, Exit.void).pipe(
355→          Effect.catchCause((cause) => Effect.logDebug("Failed to close iOS session", { cause })),
356→        );
357→        yield* Ref.set(iosSessionRef, undefined);
358→        yield* Ref.set(iosScopeRef, undefined);
359→        return {
360→          replaySessionPath: undefined,
361→          reportPath: undefined,
362→          videoPath: undefined,
363→          tmpReplaySessionPath: undefined,
364→          tmpReportPath: undefined,
365→          tmpVideoPath: undefined,
366→        } satisfies CloseResult;
367→      }
368→
369→      const activeSession = yield* Ref.get(sessionRef);
370→      if (!activeSession) return undefined;
371→
372→      yield* Ref.set(sessionRef, undefined);
373→
374→      const pollingFiber = yield* Ref.get(pollingFiberRef);
375→      if (pollingFiber) {
376→        yield* Fiber.interrupt(pollingFiber);
377→        yield* Ref.set(pollingFiberRef, undefined);
378→      }
379→
380→      const liveView = yield* Ref.get(liveViewRef);
381→      if (liveView) {
382→        yield* liveView.close.pipe(
383→          Effect.catchCause((cause) => Effect.logDebug("Failed to close live view", { cause })),
384→        );
385→        yield* Ref.set(liveViewRef, undefined);
386→      }
387→
388→      let replaySessionPath: string | undefined;
389→      let reportPath: string | undefined;
390→      let videoPath: string | undefined;
391→      let tmpReplaySessionPath: string | undefined;
392→      let tmpReportPath: string | undefined;
393→      let tmpVideoPath: string | undefined;
394→      const pageVideo = activeSession.page.video();
395→      const artifactBaseName = activeSession.replayOutputPath
396→        ? path.basename(
397→            activeSession.replayOutputPath,
398→            path.extname(activeSession.replayOutputPath),
399→          )
400→        : `session-${Date.now()}`;
401→
402→      yield* Effect.gen(function* () {
403→        if (!activeSession.page.isClosed()) {
404→          const finalEvents = yield* collectAllEvents(activeSession.page).pipe(
405→            Effect.catchCause((cause) =>
406→              Effect.logDebug("Failed to collect final replay events", { cause }).pipe(
407→                Effect.as([] as ReadonlyArray<eventWithTime>),
408→              ),
409→            ),
410→          );
411→          if (finalEvents.length > 0) {
412→            activeSession.accumulatedReplayEvents.push(...finalEvents);
413→          }
414→        }
415→
416→        const resolvedReplayOutputPath = activeSession.replayOutputPath;
417→        if (resolvedReplayOutputPath && activeSession.accumulatedReplayEvents.length > 0) {
418→          const ndjson =
419→            activeSession.accumulatedReplayEvents.map((event) => JSON.stringify(event)).join("\n") +
420→            "\n";
421→
422→          yield* fileSystem
423→            .makeDirectory(path.dirname(resolvedReplayOutputPath), { recursive: true })
424→            .pipe(
425→              Effect.catchCause((cause) =>
426→                Effect.logDebug("Failed to create replay output directory", { cause }),
427→              ),
428→            );
