270→            try: () => context.addCookies(cookies.map((cookie) => cookie.playwrightFormat)),
271→            catch: toBrowserLaunchError,
272→          });
273→        }
274→
275→        const existingPages = context.pages();
276→        const page =
277→          isCdpConnected && existingPages.length > 0
278→            ? existingPages[0]!
279→            : yield* Effect.tryPromise({
280→                try: () => context.newPage(),
281→                catch: toBrowserLaunchError,
282→              });
