284→        if (url) {
285→          yield* Effect.tryPromise({
286→            try: () => page.goto(url, { waitUntil: options.waitUntil ?? "load" }),
287→            catch: (cause) =>
288→              new NavigationError({
289→                url,
290→                cause: cause instanceof Error ? cause.message : String(cause),
291→              }),
292→          });
293→        }
294→
295→        return { browser, context, page };
296→      });
297→
298→      return yield* setupPage.pipe(
299→        Effect.tapError(() => {
300→          if (cdpEndpoint) return Effect.void;
301→          return Effect.tryPromise(() => browser.close()).pipe(
302→            Effect.catchTag("UnknownError", () => Effect.void),
303→          );
304→        }),
305→      );
306→    });
307→
308→    const snapshot = Effect.fn("Browser.snapshot")(function* (
309→      page: Page,
310→      options: SnapshotOptions = {},
311→    ) {
312→      const timeout = options.timeout ?? SNAPSHOT_TIMEOUT_MS;
313→      const selector = options.selector ?? "body";
314→      yield* Effect.annotateCurrentSpan({ selector });
315→
316→      const rawTree = yield* Effect.tryPromise({
317→        try: () => page.locator(selector).ariaSnapshot({ timeout }),
318→        catch: (cause) =>
319→          new SnapshotTimeoutError({
320→            selector,
321→            timeoutMs: timeout,
322→            cause: cause instanceof Error ? cause.message : String(cause),
323→          }),
324→      });
325→
326→      const refs: RefMap = {};
327→      const filteredLines: string[] = [];
328→      let refCount = 0;
329→
330→      for (const line of rawTree.split("\n")) {
331→        if (options.maxDepth !== undefined && getIndentLevel(line) > options.maxDepth) continue;
332→
333→        const parsed = parseAriaLine(line);
334→        if (Option.isNone(parsed)) {
335→          if (!options.interactive) filteredLines.push(line);
336→          continue;
337→        }
338→
339→        const { role, name } = parsed.value;
340→        if (options.interactive && !INTERACTIVE_ROLES.has(role)) continue;
341→
342→        if (shouldAssignRef(role, name, options.interactive)) {
343→          const ref = `${REF_PREFIX}${++refCount}`;
344→          refs[ref] = { role, name };
345→          filteredLines.push(`${line} [ref=${ref}]`);
346→        } else {
347→          filteredLines.push(line);
348→        }
349→      }
350→
351→      if (options.cursor) {
352→        refCount = yield* appendCursorInteractiveElements(
353→          page,
354→          filteredLines,
355→          refs,
356→          refCount,
357→          options,
358→        );
359→      }
360→
361→      resolveNthDuplicates(refs);
362→
363→      let tree = filteredLines.join("\n");
364→      if (options.interactive && refCount === 0) tree = "(no interactive elements)";
365→      if (options.compact) tree = compactTree(tree);
366→
367→      const stats = computeSnapshotStats(tree, refs);
368→
369→      return { tree, refs, stats, locator: createLocator(page, refs) };
370→    });
371→
372→    const act = Effect.fn("Browser.act")(function* (
373→      page: Page,
374→      ref: string,
375→      action: (locator: Locator) => Promise<void>,
376→      options?: SnapshotOptions,
377→    ) {
378→      yield* Effect.annotateCurrentSpan({ ref });
379→      const before = yield* snapshot(page, options);
380→      const locator = yield* before.locator(ref);
381→      yield* Effect.tryPromise({
382→        try: () => action(locator),
383→        catch: (error) => toActionError(error, ref),
384→      });
385→      return yield* snapshot(page, options);
386→    });
387→
388→    const annotatedScreenshot = Effect.fn("Browser.annotatedScreenshot")(function* (
389→      page: Page,
390→      options: AnnotatedScreenshotOptions = {},
391→    ) {
392→      const snapshotResult = yield* snapshot(page, options);
393→      const annotations: Annotation[] = [];
394→      const labelPositions: Array<{ label: number; x: number; y: number }> = [];
395→
396→      let labelCounter = 0;
397→
398→      for (const [ref, entry] of Object.entries(snapshotResult.refs)) {
399→        const locator = yield* snapshotResult.locator(ref);
400→        const box = yield* Effect.tryPromise(() => locator.boundingBox()).pipe(
401→          Effect.catchTag("UnknownError", () => Effect.succeed(undefined)),
402→        );
403→        if (!box) continue;
404→
405→        labelCounter++;
406→        annotations.push({ label: labelCounter, ref, role: entry.role, name: entry.name });
407→        labelPositions.push({ label: labelCounter, x: box.x, y: box.y });
408→      }
409→
410→      yield* injectOverlayLabels(page, labelPositions);
411→      return yield* Effect.ensuring(
412→        Effect.tryPromise({
413→          try: () => page.screenshot({ fullPage: options.fullPage }),
414→          catch: toBrowserLaunchError,
415→        }).pipe(Effect.map((screenshotBuffer) => ({ screenshot: screenshotBuffer, annotations }))),
416→        // HACK: overlay removal is best-effort cleanup — evaluateRuntime uses Effect.promise which defects on failure
417→        evaluateRuntime(page, "removeOverlay", OVERLAY_CONTAINER_ID).pipe(
418→          Effect.catchCause(() => Effect.void),
419→        ),
420→      );
421→    });
422→
423→    const waitForNavigationSettle = Effect.fn("Browser.waitForNavigationSettle")(function* (
424→      page: Page,
425→      urlBefore: string,
426→    ) {
427→      yield* Effect.tryPromise({
428→        try: () =>
429→          page.waitForURL((url) => url.toString() !== urlBefore, {
430→            timeout: NAVIGATION_DETECT_DELAY_MS,
431→            waitUntil: "commit",
432→          }),
433→        catch: toBrowserLaunchError,
434→      }).pipe(Effect.catchTag("BrowserLaunchError", () => Effect.void));
435→      if (page.url() !== urlBefore) {
436→        yield* Effect.tryPromise(() => page.waitForLoadState("domcontentloaded")).pipe(
437→          Effect.catchTag("UnknownError", () => Effect.void),
438→        );
439→        yield* Effect.tryPromise({
440→          try: () => page.waitForTimeout(POST_NAVIGATION_SETTLE_MS),
441→          catch: toBrowserLaunchError,
442→        });
443→      }
444→    });
445→
446→    const preExtractCookies = Effect.fn("Browser.preExtractCookies")(function* (
447→      browserKeys?: readonly string[],
448→    ) {
449→      if (browserKeys && browserKeys.length > 0) {
450→        return yield* extractCookiesForBrowserKeys(browserKeys);
451→      }
452→      const { preferredProfile } = yield* resolveDefaultBrowserContext();
453→      return yield* extractDefaultBrowserCookies("", preferredProfile);
454→    });
455→
456→    return {
457→      createPage,
458→      snapshot,
459→      act,
460→      annotatedScreenshot,
461→      waitForNavigationSettle,
462→      preExtractCookies,
463→    } as const;
464→  }),
465→}) {
466→  static layer = Layer.effect(this)(this.make);
467→}
468→
469→export const runBrowser = <A>(
470→  effect: (browser: typeof Browser.Service) => Effect.Effect<A, unknown>,
471→): Promise<A> =>
472→  Effect.runPromise(
473→    Effect.gen(function* () {
474→      const browser = yield* Browser;
475→      return yield* effect(browser);
476→    }).pipe(Effect.provide(Browser.layer)),
477→  );
